def _mechanism_impact_variables(
    metric_proxy_mapping: Sequence[Any],
    claim_text: str,
) -> list[str]:
    variables = [
        str(item).strip()
        for item in metric_proxy_mapping
        if str(item or "").strip()
    ]
    if variables:
        return list(dict.fromkeys(variables))
    text = re.sub(r"\s+", " ", str(claim_text or ""))
    inferred: list[str] = []
    for pattern, metric in METRIC_PROXY_INFERENCE_RULES:
        if re.search(pattern, text, flags=re.IGNORECASE):
            inferred.append(metric)
    return list(dict.fromkeys(inferred))


def _infer_claim_mechanism_roles(
    claim_text: str,
    *,
    target: Mapping[str, Any],
    metric_proxy_mapping: Sequence[Any],
) -> dict[str, Any]:
    text = re.sub(r"\s+", " ", str(claim_text or ""))
    channels = [
        channel
        for channel, pattern in CLAIM_MECHANISM_CHANNEL_RULES
        if re.search(pattern, text, flags=re.IGNORECASE)
    ]
    actions = [
        action
        for action, pattern in CLAIM_MECHANISM_ACTION_RULES
        if re.search(pattern, text, flags=re.IGNORECASE)
    ]
    impact_variables = _mechanism_impact_variables(metric_proxy_mapping, text)
    target_type = str(target.get("target_type") or "").strip().lower() or "unknown"
    has_mechanism = bool(channels or actions)
    connects_to_impact = has_mechanism and bool(impact_variables)
    return {
        "channels": channels,
        "actions": actions,
        "impact_variables": impact_variables,
        "has_economic_mechanism": has_mechanism,
        "mechanism_connects_to_evaluable_impact": connects_to_impact,
        "possible_operational_only_mechanism": has_mechanism and not connects_to_impact,
        "target_type": target_type,
        "mechanism_policy": "separate_regime_mechanism_capability_and_impact",
    }


def _infer_claim_component_roles(
    claim_text: str,
    *,
    target: Mapping[str, Any],
    as_of_datetime: Any = "",
    macro_regime_calendar_rows: Sequence[Mapping[str, Any]] = (),
) -> dict[str, Any]:
    text = re.sub(r"\s+", " ", str(claim_text or ""))
    text_macro_regime_types = [
        regime_type
        for regime_type, pattern in CLAIM_MACRO_REGIME_RULES
        if re.search(pattern, text, flags=re.IGNORECASE)
    ]
    (
        date_macro_regime_types,
        date_macro_regime_sources,
        date_macro_regime_details,
    ) = (
        _as_of_date_macro_regime_context(
            as_of_datetime,
            macro_regime_calendar_rows=macro_regime_calendar_rows,
        )
    )
    macro_regime_types = list(
        dict.fromkeys([*text_macro_regime_types, *date_macro_regime_types])
    )
    macro_regime_sources = {
        regime_type: "source_text" for regime_type in text_macro_regime_types
    }
    for regime_type, source in date_macro_regime_sources.items():
        macro_regime_sources.setdefault(regime_type, source)
    industry_cycle_regime_types = [
        regime_type
        for regime_type, pattern in CLAIM_INDUSTRY_CYCLE_REGIME_RULES
        if re.search(pattern, text, flags=re.IGNORECASE)
    ]
    has_company_capability = bool(CLAIM_COMPANY_CAPABILITY_RE.search(text))
    generic_regime_context = bool(CLAIM_REGIME_CONTEXT_RE.search(text))
    has_regime = bool(
        macro_regime_types
        or industry_cycle_regime_types
        or (generic_regime_context and not has_company_capability)
    )
    target_type = str(target.get("target_type") or "").strip().lower()
    return {
        "has_regime_context": has_regime,
        "has_macro_regime_context": bool(macro_regime_types),
        "has_industry_cycle_regime_context": bool(industry_cycle_regime_types),
        "regime_context_types": list(
            dict.fromkeys([*macro_regime_types, *industry_cycle_regime_types])
        ),
        "macro_regime_context_types": macro_regime_types,
        "source_text_macro_regime_context_types": text_macro_regime_types,
        "as_of_date_macro_regime_context_types": date_macro_regime_types,
        "as_of_date_macro_regime_context_details": date_macro_regime_details,
        "macro_regime_context_sources": macro_regime_sources,
        "industry_cycle_regime_context_types": industry_cycle_regime_types,
        "has_company_capability_or_action": has_company_capability,
        "has_market_or_fundamental_impact": bool(
            CLAIM_MARKET_FUNDAMENTAL_IMPACT_RE.search(text)
        ),
        "target_type": target_type or "unknown",
        "mixed_regime_and_company_capability": (
            target_type == "stock" and has_regime and has_company_capability
        ),
        "role_policy": (
            "separate_macro_regime_industry_cycle_regime_company_capability_"
            "mechanism_and_impact"
        ),
        "as_of_regime_policy": (
            "macro regime may be inferred from PIT as_of_datetime; industry-cycle "
            "regime must be source-text derived"
        ),
    }


def _target_return_metric(target: Mapping[str, Any], claim_text: str) -> str:
    target_type = str(target.get("target_type") or "").strip().lower()
    if target_type == "stock":
        return "stock_forward_return"
    if target_type in {"sector", "industry"}:
        return "industry_etf_forward_return"
    if target_type in {"bond"}:
        return "bond_etf_forward_return"
    if target_type in {"market_index", "style_index", "equity_index", "broad_market"}:
        return "equity_index_forward_return"
    if target_type in {"macro_asset", "asset_class"}:
        return "macro_asset_forward_return"
    if target_type == "commodity":
        if re.search(r"黄金|金价|贵金属", claim_text):
            return "gold_etf_forward_return"
        return "commodity_spot_price"
    if re.search(r"股价|股票|买入|增持|减持|目标价", claim_text):
        return "stock_forward_return"
    if re.search(r"板块|行业|超配|低配|跑赢|跑输", claim_text):
        return "industry_etf_forward_return"
    if re.search(r"A股|权益市场|沪深300|上证50|中证500|创业板|港股|美股|纳斯达克|标普", claim_text):
        return "equity_index_forward_return"
    if re.search(r"债券|债市|国债|利率债|信用债|城投债|固收", claim_text):
        return "bond_etf_forward_return"
    if re.search(r"黄金|金价|贵金属", claim_text):
        return "gold_etf_forward_return"
    return "forward_return_proxy"


def _normalize_metric_proxy_mapping(
    value: Any,
    *,
    claim_text: str,
    target: Mapping[str, Any],
) -> tuple[list[str], bool]:
    records = [
        str(item).strip()
        for item in _ensure_list(value)
        if str(item or "").strip()
        and str(item or "").strip().lower() not in {"unknown", "n/a", "na", "none"}
    ]
    inferred: list[str] = []
    normalized_text = re.sub(r"\s+", " ", str(claim_text or ""))
    for pattern, metric in METRIC_PROXY_INFERENCE_RULES:
        if re.search(pattern, normalized_text, flags=re.IGNORECASE):
            inferred.append(metric)
    target_type = str(target.get("target_type") or "").strip().lower()
    has_commodity_context = (
        target_type == "commodity"
        or bool(COMMODITY_PRICE_CYCLE_RE.search(normalized_text))
    )
    if not has_commodity_context:
        records = [
            item
            for item in records
            if item not in {"commodity_price_cycle", "commodity_spot_price"}
        ]
        inferred = [
            item
            for item in inferred
            if item not in {"commodity_price_cycle", "commodity_spot_price"}
        ]
    if not LIQUIDITY_CREDIT_CONTEXT_RE.search(normalized_text):
        records = [
            item for item in records if item != "liquidity_credit_condition"
        ]
        inferred = [
            item for item in inferred if item != "liquidity_credit_condition"
        ]
    if (
        target_type == "commodity"
        and "commodity_price_cycle" in inferred
    ):
        inferred.append("commodity_spot_price")
    if re.search(
        r"股价|股价表现|跑赢|跑输|超额收益|收益率|上涨|下跌|回报|买入|增持|减持|评级|目标价",
        normalized_text,
    ):
        inferred.append(_target_return_metric(target, normalized_text))
    if re.search(r"跑赢|跑输|超额收益|相对收益|alpha|阿尔法", normalized_text, flags=re.IGNORECASE):
        inferred.append("relative_alpha")

    merged: list[str] = []
    seen: set[str] = set()
    for item in [*records, *inferred]:
        key = item.lower()
        if key not in seen:
            merged.append(item)
            seen.add(key)
    return merged, bool(inferred and not records)


def _normalize_or_infer_horizon(
    horizon: Any,
    *,
    claim_text: str,
    publish_date: str,
    forecast_type: str = "",
    target: Mapping[str, Any] | None = None,
    metric_proxy_mapping: Sequence[Any] = (),
    report_level_horizon: Mapping[str, Any] | None = None,
    report_temporal_context: Mapping[str, Any] | None = None,
) -> tuple[dict[str, Any], bool]:
    normalized = _ensure_mapping(horizon)
    invalid_model_horizon = _horizon_exceeds_reasonable_bound(normalized)
    if _horizon_bucket(normalized) != "unknown" and not invalid_model_horizon:
        return normalized, False
    inferred = _infer_horizon_from_claim_text(claim_text, publish_date)
    if inferred:
        if invalid_model_horizon:
            inferred["invalid_model_horizon_replaced"] = True
        return inferred, True
    inherited = _ensure_mapping(report_level_horizon)
    temporal_context = _ensure_mapping(report_temporal_context)
    if not inherited:
        inherited = _ensure_mapping(temporal_context.get("default_horizon"))
    if inherited and _claim_may_inherit_report_level_horizon(
        claim_text,
        forecast_type=forecast_type,
        target=_ensure_mapping(target),
        metric_proxy_mapping=metric_proxy_mapping,
    ):
        inherited = dict(inherited)
        inherited.setdefault("source", "report_temporal_context")
        if inherited.get("source") == "report_level_rating_definition":
            inherited["inherited_from_report_level"] = True
        else:
            inherited["inherited_from_report_context"] = True
        if invalid_model_horizon:
            inherited["invalid_model_horizon_replaced"] = True
        return inherited, True
    if invalid_model_horizon:
        return {}, False
    return normalized, False


def _macro_claim_leg_windows_for_target_type(target_type: str) -> list[int]:
    normalized = str(target_type or "").strip().lower()
    if normalized == "macro_series":
        return [int(value) for value in MACRO_SERIES_DIRECTIONAL_WINDOWS_DAYS]
    if normalized == "macro_curve":
        return [int(value) for value in MACRO_CURVE_DIRECTIONAL_WINDOWS_DAYS]
    if normalized in MACRO_CLAIM_LEG_ASSET_TARGET_TYPES:
        return [int(value) for value in MACRO_ASSET_PROXY_WINDOWS_DAYS]
    return []


def _normalize_macro_claim_leg_evaluation_windows(
    value: Any,
    *,
    target_type: str,
) -> list[int]:
    windows: list[int] = []
    for item in _ensure_list(value):
        try:
            days = int(item)
        except (TypeError, ValueError):
            continue
        if days > 0:
            windows.append(days)
    if windows:
        return sorted(dict.fromkeys(windows))
    return _macro_claim_leg_windows_for_target_type(target_type)


def _infer_macro_claim_leg_target_type(
    target_type: Any,
    target_id: str,
    parent_target: Mapping[str, Any],
) -> str:
    normalized = str(target_type or "").strip().lower()
    if normalized:
        return normalized
    target_key = _macro_series_canonical_target_id(target_id)
    if target_key in MACRO_CURVE_DIRECTIONAL_MAPPING:
        return "macro_curve"
    if target_key in MACRO_SERIES_DIRECTIONAL_MAPPING:
        return "macro_series"
    if target_key in MACRO_ASSET_PROXY_MAPPING:
        return "macro_asset"
    return str(parent_target.get("target_type") or "").strip().lower()


def _normalize_macro_claim_leg_target(
    leg: Mapping[str, Any],
    *,
    parent_target: Mapping[str, Any],
) -> dict[str, Any]:
    nested = _ensure_mapping(leg.get("target"))
    target = dict(nested)
    target_id = str(
        leg.get("target_id")
        or nested.get("target_id")
        or nested.get("target_name")
        or ""
    ).strip()
    target_key = _macro_series_canonical_target_id(target_id)
    if target_key in (
        set(MACRO_ASSET_PROXY_MAPPING)
        | set(MACRO_SERIES_DIRECTIONAL_MAPPING)
        | set(MACRO_CURVE_DIRECTIONAL_MAPPING)
    ):
        target_id = target_key
    target_type = _infer_macro_claim_leg_target_type(
        leg.get("target_type") or nested.get("target_type"),
        target_id,
        parent_target,
    )
    target_label = str(
        leg.get("target_label")
        or nested.get("target_label")
        or nested.get("target_name")
        or target_id
    ).strip()
    if target_type:
        target["target_type"] = target_type
    if target_id:
        target["target_id"] = target_id
    if target_label:
        target["target_label"] = target_label
        target.setdefault("target_name", target_label)
    return target


def _macro_claim_leg_metric_mapping(
    leg: Mapping[str, Any],
    *,
    parent_record: Mapping[str, Any],
) -> list[str]:
    values = [
        str(item).strip()
        for item in _ensure_list(leg.get("metric_proxy_mapping"))
        if str(item or "").strip()
    ]
    for key in ("metric_proxy", "metric_family"):
        value = str(leg.get(key) or "").strip()
        if value:
            values.append(value)
    if not values:
        values.extend(
            str(item).strip()
            for item in _ensure_list(parent_record.get("metric_proxy_mapping"))
            if str(item or "").strip()
        )
    return list(dict.fromkeys(values))


def _macro_claim_leg_target_agent_candidates(
    *,
    target: Mapping[str, Any],
    metric_mapping: Sequence[Any],
    explicit_agents: Sequence[Any],
) -> list[str]:
    target_id = _macro_series_canonical_target_id(
        target.get("target_id") or target.get("target_name")
    )
    agents: list[str] = [
        *_macro_agent_ids(explicit_agents),
        *_macro_agent_ids(_ensure_list(target.get("target_agent_candidates"))),
        *_macro_agents_for_metric_families(metric_mapping),
        *MACRO_AGENT_BY_ASSET_TARGET.get(target_id, ()),
    ]
    target_type = str(target.get("target_type") or "").strip().lower()
    if target_type == "macro_series" and target_id in MACRO_SERIES_DIRECTIONAL_MAPPING:
        agents.extend(
            _macro_agent_ids(
                _ensure_list(
                    MACRO_SERIES_DIRECTIONAL_MAPPING[target_id].get(
                        "target_agent_candidates"
                    )
                )
            )
        )
    if target_type == "macro_curve" and target_id in MACRO_CURVE_DIRECTIONAL_MAPPING:
        agents.extend(
            _macro_agent_ids(
                _ensure_list(
                    MACRO_CURVE_DIRECTIONAL_MAPPING[target_id].get(
                        "target_agent_candidates"
                    )
                )
            )
        )
    return list(dict.fromkeys(agent for agent in agents if agent))


def _macro_claim_leg_source_grounding_status(
    leg: Mapping[str, Any],
    parent_record: Mapping[str, Any],
) -> str:
    explicit = str(
        leg.get("source_grounding_status")
        or leg.get("source_grounded")
        or ""
    ).strip()
    if explicit.lower() == "true":
        return "source_grounded"
    if explicit.lower() == "false":
        return "source_grounding_uncertain"
    if explicit:
        return explicit
    provenance = str(parent_record.get("claim_provenance") or "").strip()
    return provenance or "unknown"


def _is_macro_claim_leg_parent_candidate(record: Mapping[str, Any]) -> bool:
    target = _ensure_mapping(record.get("target"))
    target_type = str(target.get("target_type") or "").strip().lower()
    target_id = str(target.get("target_id") or target.get("target_name") or "").upper()
    if target_type in MACRO_CLAIM_LEG_ASSET_TARGET_TYPES | {
        "macro_series",
        "macro_curve",
        "macro_variable",
        "macro_rate",
        "macro_indicator",
    }:
        return True
    return target_id in (
        set(MACRO_ASSET_PROXY_MAPPING)
        | set(MACRO_SERIES_DIRECTIONAL_MAPPING)
        | set(MACRO_CURVE_DIRECTIONAL_MAPPING)
    )


def _normalize_single_macro_claim_leg(
    leg: Mapping[str, Any],
    *,
    parent_record: Mapping[str, Any],
    leg_index: int,
) -> dict[str, Any] | None:
    parent_target = _ensure_mapping(parent_record.get("target"))
    target = _normalize_macro_claim_leg_target(leg, parent_target=parent_target)
    target_type = str(target.get("target_type") or "").strip().lower()
    target_id = str(target.get("target_id") or target.get("target_name") or "").strip()
    if not target_type and not target_id:
        return None
    if target_type and target_type not in MACRO_CLAIM_LEG_TARGET_TYPES:
        return None
    metric_mapping = _macro_claim_leg_metric_mapping(leg, parent_record=parent_record)
    metric_family = str(
        leg.get("metric_family")
        or (metric_mapping[0] if metric_mapping else "")
    ).strip()
    direction = _normalize_forecast_direction(
        leg.get("direction") or parent_record.get("direction")
    )
    claim_horizon = _ensure_mapping(
        leg.get("claim_horizon") or leg.get("horizon")
    ) or dict(_ensure_mapping(parent_record.get("horizon")))
    normalized_leg_index = _int_or_none(leg.get("leg_index")) or leg_index
    parent_claim_id = str(parent_record.get("forecast_claim_id") or "")
    explicit_agents = [
        *_ensure_list(leg.get("target_agent_candidates")),
        *_ensure_list(leg.get("target_agents")),
    ]
    target_agent_candidates = _macro_claim_leg_target_agent_candidates(
        target=target,
        metric_mapping=metric_mapping,
        explicit_agents=explicit_agents,
    )
    leg_id = _stable_id(
        "MCL",
        {
            "parent_forecast_claim_id": parent_claim_id,
            "leg_index": normalized_leg_index,
            "target_type": target_type,
            "target_id": target_id,
            "metric_mapping": metric_mapping,
            "direction": direction,
        },
    )
    return {
        "schema_version": MACRO_CLAIM_LEG_SCHEMA_VERSION,
        "parent_forecast_claim_id": parent_claim_id,
        "macro_claim_leg_id": leg_id,
        "leg_index": normalized_leg_index,
        "target_type": target_type,
        "target_id": target_id,
        "target_label": str(target.get("target_label") or target_id),
        "target": target,
        "metric_family": metric_family,
        "metric_proxy": str(leg.get("metric_proxy") or metric_family),
        "metric_proxy_mapping": metric_mapping,
        "direction": direction,
        "quote_convention": str(leg.get("quote_convention") or "").strip(),
        "orientation_rule": str(leg.get("orientation_rule") or "").strip(),
        "claim_horizon": claim_horizon,
        "evaluation_windows": _normalize_macro_claim_leg_evaluation_windows(
            leg.get("evaluation_windows"),
            target_type=target_type,
        ),
        "source_grounding_status": _macro_claim_leg_source_grounding_status(
            leg,
            parent_record,
        ),
        "target_agent_candidates": target_agent_candidates,
    }


def _primary_macro_claim_leg(parent_record: Mapping[str, Any]) -> dict[str, Any] | None:
    if not _is_macro_claim_leg_parent_candidate(parent_record):
        return None
    target = _ensure_mapping(parent_record.get("target"))
    metric_mapping = [
        str(item).strip()
        for item in _ensure_list(parent_record.get("metric_proxy_mapping"))
        if str(item or "").strip()
    ]
    leg = {
        "leg_index": 1,
        "target": target,
        "target_type": target.get("target_type"),
        "target_id": target.get("target_id") or target.get("target_name"),
        "target_label": target.get("target_label") or target.get("target_name"),
        "metric_proxy_mapping": metric_mapping,
        "direction": parent_record.get("direction"),
        "claim_horizon": parent_record.get("horizon"),
        "source_grounding_status": parent_record.get("claim_provenance"),
        "target_agent_candidates": parent_record.get("target_agent_candidates"),
    }
    return _normalize_single_macro_claim_leg(
        leg,
        parent_record=parent_record,
        leg_index=1,
    )


def _normalize_macro_claim_legs(
    value: Any,
    *,
    parent_record: Mapping[str, Any],
) -> list[dict[str, Any]]:
    legs: list[dict[str, Any]] = []
    for fallback_index, item in enumerate(_ensure_list(value), 1):
        if len(legs) >= MAX_MACRO_CLAIM_LEGS_PER_PARENT:
            break
        leg = _normalize_single_macro_claim_leg(
            _ensure_mapping(item),
            parent_record=parent_record,
            leg_index=fallback_index,
        )
        if leg is not None:
            legs.append(leg)
    primary_leg = _primary_macro_claim_leg(parent_record)
    if legs:
        if _should_prepend_primary_macro_claim_leg(legs, primary_leg):
            legs.insert(0, primary_leg)
        return _renumber_macro_claim_legs(
            legs[:MAX_MACRO_CLAIM_LEGS_PER_PARENT],
            parent_record=parent_record,
        )
    return [primary_leg] if primary_leg is not None else []


def _macro_claim_leg_target_key(leg: Mapping[str, Any]) -> tuple[str, str]:
    return (
        str(leg.get("target_type") or "").strip().lower(),
        str(leg.get("target_id") or "").strip().upper(),
    )


def _should_prepend_primary_macro_claim_leg(
    legs: Sequence[Mapping[str, Any]],
    primary_leg: Mapping[str, Any] | None,
) -> bool:
    if primary_leg is None:
        return False
    primary_key = _macro_claim_leg_target_key(primary_leg)
    if primary_key[0] not in {"macro_curve", "macro_series"} or not primary_key[1]:
        return False
    return primary_key not in {_macro_claim_leg_target_key(leg) for leg in legs}


def _renumber_macro_claim_legs(
    legs: Sequence[Mapping[str, Any]],
    *,
    parent_record: Mapping[str, Any],
) -> list[dict[str, Any]]:
    parent_claim_id = str(parent_record.get("forecast_claim_id") or "")
    renumbered: list[dict[str, Any]] = []
    for index, leg in enumerate(legs, 1):
        updated = dict(leg)
        updated["leg_index"] = index
        updated["macro_claim_leg_id"] = _stable_id(
            "MCL",
            {
                "parent_forecast_claim_id": parent_claim_id,
                "leg_index": index,
                "target_type": str(updated.get("target_type") or "").strip().lower(),
                "target_id": str(
                    updated.get("target_id") or updated.get("target_name") or ""
                ).strip(),
                "metric_mapping": [
                    str(item).strip()
                    for item in _ensure_list(updated.get("metric_proxy_mapping"))
                    if str(item or "").strip()
                ],
                "direction": _normalize_forecast_direction(updated.get("direction")),
            },
        )
        renumbered.append(updated)
    return renumbered


def _macro_claim_leg_forecast_type(
    leg: Mapping[str, Any],
    parent_record: Mapping[str, Any],
) -> str:
    explicit = str(leg.get("forecast_type") or "").strip()
    if explicit:
        return explicit
    target_type = str(leg.get("target_type") or "").strip().lower()
    if target_type == "macro_series":
        return "macro_series_directional"
    if target_type == "macro_curve":
        return "macro_curve_directional"
    if target_type in MACRO_CLAIM_LEG_ASSET_TARGET_TYPES:
        return "macro_asset_proxy"
    return str(parent_record.get("forecast_type") or "unknown")


def _forecast_row_from_macro_claim_leg(
    parent_record: Mapping[str, Any],
    leg: Mapping[str, Any],
) -> dict[str, Any]:
    row = dict(parent_record)
    extraction_quality = dict(_ensure_mapping(parent_record.get("extraction_quality")))
    target = dict(_ensure_mapping(leg.get("target")))
    row.update(
        {
            "parent_forecast_claim_id": str(
                leg.get("parent_forecast_claim_id")
                or parent_record.get("forecast_claim_id")
                or ""
            ),
            "macro_claim_leg_id": str(leg.get("macro_claim_leg_id") or ""),
            "macro_claim_leg_index": _int_or_none(leg.get("leg_index")),
            "macro_claim_leg": dict(leg),
            "forecast_type": _macro_claim_leg_forecast_type(leg, parent_record),
            "target": target,
            "direction": _normalize_forecast_direction(
                leg.get("direction") or parent_record.get("direction")
            ),
            "horizon": dict(
                _ensure_mapping(leg.get("claim_horizon"))
                or _ensure_mapping(parent_record.get("horizon"))
            ),
            "metric_proxy_mapping": [
                str(item).strip()
                for item in _ensure_list(leg.get("metric_proxy_mapping"))
                if str(item or "").strip()
            ],
            "target_agent_candidates": [
                str(agent)
                for agent in _ensure_list(leg.get("target_agent_candidates"))
                if str(agent).strip()
            ],
        }
    )
    extraction_quality["macro_claim_leg_expanded"] = True
    extraction_quality["parent_forecast_claim_id"] = row["parent_forecast_claim_id"]
    extraction_quality["macro_claim_leg_id"] = row["macro_claim_leg_id"]
    extraction_quality["macro_claim_leg_index"] = row["macro_claim_leg_index"]
    row["extraction_quality"] = extraction_quality
    return row


def _forecast_rows_with_macro_claim_legs(
    forecast_rows: Sequence[Mapping[str, Any]],
) -> list[dict[str, Any]]:
    expanded: list[dict[str, Any]] = []
    for row in forecast_rows:
        if str(row.get("macro_claim_leg_id") or "").strip():
            expanded.append(dict(row))
            continue
        legs = _normalize_macro_claim_legs(
            row.get("macro_claim_legs"),
            parent_record=row,
        )
        if not legs:
            expanded.append(dict(row))
            continue
        expanded.extend(_forecast_row_from_macro_claim_leg(row, leg) for leg in legs)
    return expanded


def _macro_claim_leg_trace_fields(claim: Mapping[str, Any]) -> dict[str, Any]:
    leg_id = str(claim.get("macro_claim_leg_id") or "").strip()
    if not leg_id:
        return {}
    fields: dict[str, Any] = {
        "parent_forecast_claim_id": str(
            claim.get("parent_forecast_claim_id")
            or claim.get("forecast_claim_id")
            or ""
        ),
        "macro_claim_leg_id": leg_id,
    }
    leg_index = _int_or_none(claim.get("macro_claim_leg_index"))
    if leg_index is not None:
        fields["macro_claim_leg_index"] = leg_index
    return fields


def _macro_asset_proxy_target_agent_candidates(
    claim: Mapping[str, Any],
    proxy: Mapping[str, Any],
) -> list[str]:
    target = _ensure_mapping(claim.get("target"))
    target_id = str(proxy.get("target_id") or target.get("target_id") or "").upper()
    agents: list[str] = [*MACRO_AGENT_BY_ASSET_TARGET.get(target_id, ())]
    if not agents:
        agents.extend(
            [
                *_macro_agent_ids(_ensure_list(claim.get("target_agent_candidates"))),
                *_macro_agent_ids(_ensure_list(target.get("target_agent_candidates"))),
                *_macro_agents_for_metric_families(_claim_metric_families(claim)),
            ]
        )
    return list(dict.fromkeys(agent for agent in agents if agent))


def _forecast_mapping_gaps(record: Mapping[str, Any]) -> list[str]:
    gaps: list[str] = []
    target = _ensure_mapping(record.get("target"))
    benchmark = _ensure_mapping(record.get("benchmark"))
    horizon = _ensure_mapping(record.get("horizon"))
    direction = _normalize_forecast_direction(record.get("direction"))
    macro_claim_legs = _ensure_list(record.get("macro_claim_legs"))
    leg_targets = [
        _ensure_mapping(leg).get("target_id")
        or _ensure_mapping(_ensure_mapping(leg).get("target")).get("target_id")
        for leg in macro_claim_legs
    ]
    leg_directions = [
        _normalize_forecast_direction(_ensure_mapping(leg).get("direction"))
        for leg in macro_claim_legs
    ]
    leg_horizons = [
        _ensure_mapping(_ensure_mapping(leg).get("claim_horizon"))
        for leg in macro_claim_legs
    ]
    if _target_id(target) == "unknown" and not any(
        str(item or "").strip() for item in leg_targets
    ):
        gaps.append("target")
    if not benchmark:
        gaps.append("benchmark")
    if direction in {"", "unknown", "ambiguous"} and not any(
        item in {"positive", "negative"} for item in leg_directions
    ):
        gaps.append("direction")
    if _horizon_bucket(horizon) == "unknown" and not any(
        _horizon_bucket(item) != "unknown" for item in leg_horizons
    ):
        gaps.append("horizon")
    return gaps


def _explicit_agent_candidates(record: Mapping[str, Any]) -> list[str]:
    target = _ensure_mapping(record.get("target"))
    values: list[Any] = []
    for payload in (record, target):
        for key in (
            "target_agent_candidates",
            "target_agents",
            "owner_agent",
            "owner_agent_id",
            "owning_agent",
            "owning_agent_id",
            "agent_id",
        ):
            raw = payload.get(key)
            values.extend(_ensure_list(raw) if isinstance(raw, list | tuple) else [raw])
    return list(
        dict.fromkeys(
            agent_id for value in values if (agent_id := _known_agent_id(value))
        )
    )


def _sector_assignment_agent_candidates(record: Mapping[str, Any]) -> list[str]:
    from .agent_research_context import SECTOR_AGENT_KEYWORDS

    target = _ensure_mapping(record.get("target"))
    text = " ".join(
        str(value)
        for value in (
            target.get("target_id"),
            target.get("target_name"),
            target.get("target_label"),
            record.get("sector"),
        )
        if str(value or "").strip()
    ).lower()
    agents = [
        agent_id
        for agent_id, keywords in SECTOR_AGENT_KEYWORDS.items()
        if any(str(keyword).lower() in text for keyword in keywords)
    ]
    agents.extend(INDUSTRY_ASSIGNMENT_FALLBACK_AGENT_CANDIDATES)
    return list(dict.fromkeys(agents))


def _inferred_agent_assignment(record: Mapping[str, Any]) -> tuple[str, list[str]]:
    target = _ensure_mapping(record.get("target"))
    target_type = str(target.get("target_type") or "").strip().lower()
    if target_type.startswith("macro"):
        agents = list(_claim_macro_agent_candidates(record))
        return ("macro_target_mapping", agents) if agents else ("", [])
    if target_type in {"stock", "company"}:
        return "stock_default_agents", list(STOCK_ASSIGNMENT_AGENT_CANDIDATES)
    if target_type in {"sector", "industry"}:
        return "industry_default_agents", _sector_assignment_agent_candidates(record)
    return "", []


def _assignment_gaps(record: Mapping[str, Any]) -> list[str]:
    target = _ensure_mapping(record.get("target"))
    target_type = str(target.get("target_type") or "").strip()
    target_id = _target_id(target)
    if (
        target_type in {"", "unknown"}
        or target_id == "unknown"
        or not _claim_metric_families(record)
    ):
        return []
    if _explicit_agent_candidates(record):
        return []
    if _inferred_agent_assignment(record)[1]:
        return []
    return ["agent_assignment_missing"]


PRE_REVIEW_DECISIONS = {"include", "exclude", "rewrite_needed"}


def _normalize_analyst_claim(
    claim: Mapping[str, Any],
    fallback_claim_text: str,
) -> tuple[str, bool]:
    raw = _record_text(
        claim,
        "analyst_claim",
        "refined_claim",
        "financial_practitioner_claim",
    )
    if not raw:
        return fallback_claim_text, False
    analyst_claim, truncated = _bounded_claim_text(raw)
    return analyst_claim, analyst_claim != fallback_claim_text or truncated


def _normalized_pre_review_decision(value: Any) -> str:
    decision = str(value or "").strip().lower()
    return decision if decision in PRE_REVIEW_DECISIONS else ""


def _forecast_claim_pre_review(
    record: Mapping[str, Any],
    *,
    component_roles: Mapping[str, Any],
    mechanism_roles: Mapping[str, Any],
    mapping_gaps: Sequence[str],
    analyst_claim_adjusted: bool,
    llm_decision: Any = "",
    llm_reason: Any = "",
) -> dict[str, Any]:
    direction = _normalize_forecast_direction(record.get("direction"))
    target = _ensure_mapping(record.get("target"))
    guardrail_blockers: list[str] = []
    if str(record.get("claim_provenance") or "") != "source_grounded":
        guardrail_blockers.append("not_source_grounded")
    if direction not in {"positive", "negative"}:
        guardrail_blockers.append("direction_missing_or_not_actionable")
    if _target_id(target) == "unknown":
        guardrail_blockers.append("target_missing")
    if component_roles.get("has_market_or_fundamental_impact") is not True:
        guardrail_blockers.append("market_or_fundamental_impact_missing")
    if mechanism_roles.get("has_economic_mechanism") is not True:
        guardrail_blockers.append("economic_mechanism_missing")
    if mechanism_roles.get("mechanism_connects_to_evaluable_impact") is not True:
        guardrail_blockers.append("mechanism_to_impact_link_missing")
    if is_non_research_claim_text(str(record.get("claim_text") or "")):
        guardrail_blockers.append("non_research_or_boilerplate_text")

    model_decision = _normalized_pre_review_decision(llm_decision)
    if guardrail_blockers:
        decision = "exclude"
        decision_source = "deterministic_guardrail"
    elif model_decision:
        decision = model_decision
        decision_source = "llm_financial_practitioner"
    elif mapping_gaps or component_roles.get("has_regime_context") is not True:
        decision = "rewrite_needed"
        decision_source = "deterministic_guardrail"
    else:
        decision = "include"
        decision_source = "deterministic_guardrail"

    reason = str(llm_reason or "").strip()
    if not reason:
        if guardrail_blockers:
            reason = "guardrail blockers: " + ", ".join(guardrail_blockers)
        elif mapping_gaps:
            reason = "mapping gaps require human confirmation: " + ", ".join(mapping_gaps)
        elif component_roles.get("has_regime_context") is not True:
            reason = "claim has mechanism and impact but lacks explicit regime context"
        else:
            reason = (
                "source-grounded financial thesis with direction, target, mechanism, "
                "and finance-relevant impact"
            )

    return {
        "schema_version": "forecast_claim_pre_review_v1",
        "perspective": "financial_practitioner",
        "decision": decision,
        "decision_source": decision_source,
        "reason": reason,
        "guardrail_blockers": guardrail_blockers,
        "mapping_gaps": list(mapping_gaps),
        "quality_checks": {
            "source_grounded": str(record.get("claim_provenance") or "") == "source_grounded",
            "has_macro_regime_context": component_roles.get("has_macro_regime_context") is True,
            "has_industry_cycle_regime_context": (
                component_roles.get("has_industry_cycle_regime_context") is True
            ),
            "has_company_capability_or_action": (
                component_roles.get("has_company_capability_or_action") is True
            ),
            "has_economic_mechanism": mechanism_roles.get("has_economic_mechanism") is True,
            "mechanism_connects_to_evaluable_impact": (
                mechanism_roles.get("mechanism_connects_to_evaluable_impact") is True
            ),
            "has_market_or_fundamental_impact": (
                component_roles.get("has_market_or_fundamental_impact") is True
            ),
            "has_target": _target_id(target) != "unknown",
            "has_direction": direction in {"positive", "negative"},
            "has_horizon": _horizon_bucket(_ensure_mapping(record.get("horizon"))) != "unknown",
            "analyst_claim_adjusted": analyst_claim_adjusted,
        },
        "claim_regime_trace_policy": "background_only_not_claim_validation",
    }


def _normalize_forecast_claims(
    payload: Mapping[str, Any],
    row: Mapping[str, Any],
    *,
    run_id: str,
    model: str,
    report_id: str,
    chunk_span_id: str,
    macro_regime_calendar_rows: Sequence[Mapping[str, Any]] = (),
    report_level_horizon: Mapping[str, Any] | None = None,
    report_temporal_context: Mapping[str, Any] | None = None,
    report_context: Mapping[str, Any] | None = None,
    section_context: Mapping[str, Any] | None = None,
) -> list[dict[str, Any]]:
    records: list[dict[str, Any]] = []
    for item in _ensure_list(payload.get("forecast_claims")):
        claim = _ensure_mapping(item)
        raw_claim_text = _record_text(claim, "claim_text", "text")
        if not raw_claim_text:
            continue
        target = _ensure_mapping(claim.get("target"))
        stock_subject = _stock_subject_from_metadata(row)
        target, stock_target_bound = _target_with_metadata_stock_subject(
            target,
            stock_subject,
        )
        raw_claim_text, claim_subject_bound = _bind_stock_subject_to_text(
            raw_claim_text,
            target=target,
            stock_subject=stock_subject,
        )
        metric_proxy_mapping, metric_proxy_inferred = _normalize_metric_proxy_mapping(
            claim.get("metric_proxy_mapping"),
            claim_text=raw_claim_text,
            target=target,
        )
        claim_text, claim_text_truncated = _bounded_claim_text(raw_claim_text)
        analyst_claim, analyst_claim_adjusted = _normalize_analyst_claim(
            claim,
            claim_text,
        )
        analyst_claim, analyst_subject_bound = _bind_stock_subject_to_text(
            analyst_claim,
            target=target,
            stock_subject=stock_subject,
        )
        analyst_claim_adjusted = (
            analyst_claim_adjusted or claim_subject_bound or analyst_subject_bound
        )
        forecast_type = str(claim.get("forecast_type") or "unknown")
        horizon, horizon_inferred = _normalize_or_infer_horizon(
            claim.get("horizon"),
            claim_text=raw_claim_text,
            publish_date=str(row.get("publish_date") or ""),
            forecast_type=forecast_type,
            target=target,
            metric_proxy_mapping=metric_proxy_mapping,
            report_level_horizon=report_level_horizon,
            report_temporal_context=report_temporal_context,
        )
        record = {
            "forecast_claim_id": _stable_id(
                "FC",
                {
                    "report_id": report_id,
                    "chunk_span_id": chunk_span_id,
                    "claim_text": claim_text,
                },
            ),
            "claim_id": _stable_id(
                "CLAIM",
                {
                    "report_id": report_id,
                    "claim_text": claim_text,
                },
            ),
            "report_id": report_id,
            "source_id": str(row.get("source_id") or ""),
            "source_span_ids": _source_span_ids(claim, chunk_span_id),
            "claim_text": claim_text,
            "analyst_claim": analyst_claim,
            "claim_provenance": _normalize_claim_provenance(
                claim.get("claim_provenance")
            ),
            "forecast_testability": str(
                claim.get("forecast_testability") or "insufficient_mapping"
            ),
            "forecast_type": forecast_type,
            "target": target,
            "benchmark": _ensure_mapping(claim.get("benchmark")),
            "direction": _normalize_forecast_direction(claim.get("direction")),
            "horizon": horizon,
            "signal_datetime": str(row.get("publish_date") or ""),
            "entry_rule": _ensure_mapping(claim.get("entry_rule")),
            "explicitness": str(claim.get("explicitness") or "unknown"),
            "source_conviction": str(claim.get("source_conviction") or "unknown"),
            "metric_proxy_mapping": metric_proxy_mapping,
            "failure_modes": _normalize_failure_modes(claim.get("failure_modes")),
            "extraction_quality": _ensure_mapping(claim.get("extraction_quality")),
            "extractor": {
                "run_id": run_id,
                "model": model,
                "input_mode": "original_markdown",
            },
        }
        if not _is_forecast_claim_candidate_record(
            record,
            raw_claim_text,
            target=target,
            metric_proxy_mapping=metric_proxy_mapping,
        ):
            continue
        record["extraction_quality"][
            "claim_text_truncated_for_redaction"
        ] = claim_text_truncated
        if record["claim_provenance"] == "source_grounded":
            record["extraction_quality"].setdefault("span_grounded", True)
        context = dict(_ensure_mapping(report_context))
        if not context:
            subject_context = _infer_report_subject_context(row)
            if subject_context:
                context["subject_context"] = subject_context
        section = _ensure_mapping(section_context)
        if section:
            context["section_context"] = dict(section)
        if context:
            record["extraction_quality"]["report_context"] = context
        if stock_target_bound:
            record["extraction_quality"]["stock_target_bound_from_metadata"] = True
        if claim_subject_bound or analyst_subject_bound:
            record["extraction_quality"]["stock_subject_bound_from_metadata"] = True
            record["extraction_quality"]["stock_subject_label"] = stock_subject.get(
                "subject_label",
                "",
            )
            record["extraction_quality"]["claim_text_stock_subject_bound"] = (
                claim_subject_bound
            )
            record["extraction_quality"]["analyst_claim_stock_subject_bound"] = (
                analyst_subject_bound
            )
        component_roles = _infer_claim_component_roles(
            raw_claim_text,
            target=target,
            as_of_datetime=row.get("publish_date"),
            macro_regime_calendar_rows=macro_regime_calendar_rows,
        )
        record["extraction_quality"]["claim_component_roles"] = component_roles
        record["claim_regime_trace"] = _build_claim_regime_trace(
            as_of_datetime=row.get("publish_date"),
            target=target,
            component_roles=component_roles,
        )
        mechanism_roles = _infer_claim_mechanism_roles(
            raw_claim_text,
            target=target,
            metric_proxy_mapping=metric_proxy_mapping,
        )
        record["extraction_quality"]["claim_mechanism_roles"] = mechanism_roles
        macro_claim_legs = _normalize_macro_claim_legs(
            claim.get("macro_claim_legs"),
            parent_record=record,
        )
        if macro_claim_legs:
            record["macro_claim_legs"] = macro_claim_legs
            record["extraction_quality"]["macro_claim_leg_count"] = len(
                macro_claim_legs
            )
            record["extraction_quality"][
                "macro_claim_leg_policy"
            ] = "parent_claim_preserves_full_thesis_child_legs_drive_macro_outcomes"
        if horizon_inferred:
            if horizon.get("source") == "report_level_rating_definition":
                record["extraction_quality"][
                    "horizon_inferred_from_report_level"
                ] = True
                record["extraction_quality"]["report_level_horizon"] = dict(horizon)
                record["extraction_quality"][
                    "report_level_horizon_source_text"
                ] = horizon.get("source_text", "")
            elif horizon.get("source") in {
                "report_temporal_context",
                "section_context",
                "report_type_default",
            }:
                record["extraction_quality"][
                    "horizon_inferred_from_report_temporal_context"
                ] = True
                record["extraction_quality"]["report_temporal_context"] = dict(
                    _ensure_mapping(report_temporal_context)
                )
                record["extraction_quality"][
                    "report_temporal_context_source_text"
                ] = horizon.get("source_text", "")
            else:
                record["extraction_quality"][
                    "horizon_inferred_from_claim_text"
                ] = True
                record["extraction_quality"][
                    "horizon_inference_source_text"
                ] = horizon.get(
                    "source_text",
                    "",
                )
        if metric_proxy_inferred:
            record["extraction_quality"][
                "metric_proxy_mapping_inferred_from_claim_text"
            ] = True
        mapping_gaps = _forecast_mapping_gaps(record)
        if mapping_gaps:
            record["forecast_testability"] = "insufficient_mapping"
            record["extraction_quality"]["mapping_gaps"] = mapping_gaps
            record["extraction_quality"]["needs_human_review"] = True
        record["pre_review"] = _forecast_claim_pre_review(
            record,
            component_roles=component_roles,
            mechanism_roles=mechanism_roles,
            mapping_gaps=mapping_gaps,
            analyst_claim_adjusted=analyst_claim_adjusted,
            llm_decision=claim.get("pre_review_decision"),
            llm_reason=claim.get("pre_review_reason"),
        )
        records.append(record)
    return records


def _forecast_claim_selection_score(record: Mapping[str, Any]) -> tuple[int, ...]:
    target = _ensure_mapping(record.get("target"))
    horizon = _ensure_mapping(record.get("horizon"))
    extraction_quality = _ensure_mapping(record.get("extraction_quality"))
    component_roles = _ensure_mapping(extraction_quality.get("claim_component_roles"))
    mechanism_roles = _ensure_mapping(extraction_quality.get("claim_mechanism_roles"))
    conviction = str(record.get("source_conviction") or "").strip().lower()
    conviction_rank = {
        "very_high": 4,
        "high": 3,
        "strong": 3,
        "medium": 2,
        "moderate": 2,
        "low": 1,
        "weak": 1,
    }.get(conviction, 0)
    return (
        int(record.get("claim_provenance") == "source_grounded"),
        int(record.get("forecast_testability") == "testable"),
        int(
            _normalize_forecast_direction(record.get("direction"))
            in {"positive", "negative"}
        ),
        int(_target_id(target) != "unknown"),
        int(_horizon_bucket(horizon) != "unknown"),
        int(bool(_ensure_list(record.get("metric_proxy_mapping")))),
        int(mechanism_roles.get("has_economic_mechanism") is True),
        int(
            mechanism_roles.get("mechanism_connects_to_evaluable_impact")
            is True
        ),
        int(component_roles.get("has_regime_context") is True),
        conviction_rank,
    )


def _top_forecast_claim_indices(
    indexed_records: Sequence[tuple[int, Mapping[str, Any]]],
    *,
    limit: int,
) -> set[int]:
    ranked = sorted(
        indexed_records,
        key=lambda item: (_forecast_claim_selection_score(item[1]), -item[0]),
        reverse=True,
    )
    return {index for index, _record in ranked[:limit]}


def _select_report_forecast_claims(
    records: Sequence[Mapping[str, Any]],
    *,
    limit: int = MAX_FORECAST_CLAIMS_PER_REPORT,
) -> list[dict[str, Any]]:
    if limit <= 0:
        return []
    if len(records) <= limit:
        return [dict(record) for record in records]
    selected_indices = _top_forecast_claim_indices(tuple(enumerate(records)), limit=limit)
    return [
        dict(record)
        for index, record in enumerate(records)
        if index in selected_indices
    ]


def _select_forecast_claims_per_report(
    records: Sequence[Mapping[str, Any]],
    *,
    limit: int = MAX_FORECAST_CLAIMS_PER_REPORT,
) -> list[dict[str, Any]]:
    if limit <= 0:
        return []
    buckets: dict[str, list[tuple[int, Mapping[str, Any]]]] = defaultdict(list)
    for index, record in enumerate(records):
        report_key = str(record.get("report_id") or record.get("source_id") or "unknown")
        buckets[report_key].append((index, record))
    selected_indices: set[int] = set()
    for indexed_records in buckets.values():
        if len(indexed_records) <= limit:
            selected_indices.update(index for index, _record in indexed_records)
            continue
        selected_indices.update(
            _top_forecast_claim_indices(tuple(indexed_records), limit=limit)
        )
    return [
        dict(record)
        for index, record in enumerate(records)
        if index in selected_indices
    ]


def _refresh_forecast_mapping_governance(
    forecast_rows: Sequence[Mapping[str, Any]],
    *,
    metadata_rows: Sequence[Mapping[str, Any]] = (),
    macro_regime_calendar_rows: Sequence[Mapping[str, Any]] = (),
    root_path: Path | None = None,
) -> list[dict[str, Any]]:
    metadata_by_source = _source_report_metadata(metadata_rows) if metadata_rows else {}
    report_context_by_source = _report_context_by_source_from_metadata(
        metadata_rows,
        root_path=root_path,
    )
    report_level_horizon_by_source = _report_level_horizon_by_source_from_metadata(
        metadata_rows,
        root_path=root_path,
    )
    report_temporal_context_by_source = _report_temporal_context_by_source_from_metadata(
        metadata_rows,
        root_path=root_path,
    )
    refreshed_rows: list[dict[str, Any]] = []
    for row in forecast_rows:
        refreshed = dict(row)
        source_id = str(refreshed.get("source_id") or "")
        target = _ensure_mapping(refreshed.get("target"))
        metadata = metadata_by_source.get(source_id) or {}
        stock_subject = _stock_subject_from_metadata(metadata)
        target, stock_target_bound = _target_with_metadata_stock_subject(
            target,
            stock_subject,
        )
        claim_text = str(refreshed.get("claim_text") or "")
        claim_text, claim_subject_bound = _bind_stock_subject_to_text(
            claim_text,
            target=target,
            stock_subject=stock_subject,
        )
        analyst_claim = str(refreshed.get("analyst_claim") or "").strip()
        if not analyst_claim:
            analyst_claim = claim_text
        analyst_claim, analyst_subject_bound = _bind_stock_subject_to_text(
            analyst_claim,
            target=target,
            stock_subject=stock_subject,
        )
        analyst_claim_adjusted = bool(
            analyst_claim != claim_text or claim_subject_bound or analyst_subject_bound
        )
        refreshed["claim_text"] = claim_text
        refreshed["analyst_claim"] = analyst_claim
        refreshed["target"] = target
        if claim_subject_bound:
            report_id = str(refreshed.get("report_id") or "")
            source_span_ids = _ensure_list(refreshed.get("source_span_ids"))
            chunk_span_id = str(source_span_ids[0] if source_span_ids else "")
            if report_id:
                refreshed["claim_id"] = _stable_id(
                    "CLAIM",
                    {"report_id": report_id, "claim_text": claim_text},
                )
            if report_id and chunk_span_id:
                refreshed["forecast_claim_id"] = _stable_id(
                    "FC",
                    {
                        "report_id": report_id,
                        "chunk_span_id": chunk_span_id,
                        "claim_text": claim_text,
                    },
                )
        metric_proxy_mapping, metric_proxy_inferred = _normalize_metric_proxy_mapping(
            refreshed.get("metric_proxy_mapping"),
            claim_text=claim_text,
            target=target,
        )
        if not _is_forecast_claim_candidate_record(
            refreshed,
            claim_text,
            target=target,
            metric_proxy_mapping=metric_proxy_mapping,
        ):
            continue
        extraction_quality = dict(_ensure_mapping(refreshed.get("extraction_quality")))
        report_context = _ensure_mapping(extraction_quality.get("report_context"))
        if not report_context:
            report_context = report_context_by_source.get(source_id, {})
        if report_context:
            extraction_quality["report_context"] = dict(report_context)
        report_level_horizon = _ensure_mapping(
            extraction_quality.get("report_level_horizon")
        )
        if not report_level_horizon:
            report_level_horizon = report_level_horizon_by_source.get(source_id, {})
        report_temporal_context = _ensure_mapping(
            extraction_quality.get("report_temporal_context")
        )
        if not report_temporal_context:
            report_temporal_context = _ensure_mapping(
                report_context.get("temporal_context")
            )
        if not report_temporal_context:
            report_temporal_context = report_temporal_context_by_source.get(source_id, {})
        forecast_type = str(refreshed.get("forecast_type") or "unknown")
        horizon, horizon_inferred = _normalize_or_infer_horizon(
            refreshed.get("horizon"),
            claim_text=claim_text,
            publish_date=str(
                refreshed.get("signal_datetime")
                or refreshed.get("publish_date")
                or "",
            ),
            forecast_type=forecast_type,
            target=target,
            metric_proxy_mapping=metric_proxy_mapping,
            report_level_horizon=report_level_horizon,
            report_temporal_context=report_temporal_context,
        )
        refreshed["horizon"] = horizon
        if stock_target_bound:
            extraction_quality["stock_target_bound_from_metadata"] = True
        if claim_subject_bound or analyst_subject_bound:
            extraction_quality["stock_subject_bound_from_metadata"] = True
            extraction_quality["stock_subject_label"] = stock_subject.get(
                "subject_label",
                "",
            )
            extraction_quality["claim_text_stock_subject_bound"] = claim_subject_bound
            extraction_quality["analyst_claim_stock_subject_bound"] = (
                analyst_subject_bound
            )
        refreshed["metric_proxy_mapping"] = metric_proxy_mapping
        if horizon_inferred:
            if horizon.get("source") == "report_level_rating_definition":
                extraction_quality.pop("horizon_inferred_from_claim_text", None)
                extraction_quality.pop("horizon_inference_source_text", None)
                extraction_quality.pop(
                    "horizon_inferred_from_report_temporal_context",
                    None,
                )
                extraction_quality["horizon_inferred_from_report_level"] = True
                extraction_quality["report_level_horizon"] = dict(horizon)
                extraction_quality["report_level_horizon_source_text"] = horizon.get(
                    "source_text",
                    "",
                )
            elif horizon.get("source") in {
                "report_temporal_context",
                "section_context",
                "report_type_default",
            }:
                extraction_quality.pop("horizon_inferred_from_claim_text", None)
                extraction_quality.pop("horizon_inference_source_text", None)
                extraction_quality.pop("horizon_inferred_from_report_level", None)
                extraction_quality.pop("report_level_horizon_source_text", None)
                extraction_quality[
                    "horizon_inferred_from_report_temporal_context"
                ] = True
                extraction_quality["report_temporal_context"] = dict(
                    report_temporal_context
                )
                extraction_quality[
                    "report_temporal_context_source_text"
                ] = horizon.get("source_text", "")
            else:
                extraction_quality.pop("horizon_inferred_from_report_level", None)
                extraction_quality.pop("report_level_horizon_source_text", None)
                extraction_quality.pop(
                    "horizon_inferred_from_report_temporal_context",
                    None,
                )
                extraction_quality["horizon_inferred_from_claim_text"] = True
                extraction_quality["horizon_inference_source_text"] = horizon.get(
                    "source_text",
                    "",
                )
        if metric_proxy_inferred:
            extraction_quality["metric_proxy_mapping_inferred_from_claim_text"] = True
        component_roles = _infer_claim_component_roles(
            claim_text,
            target=target,
            as_of_datetime=(
                refreshed.get("signal_datetime")
                or refreshed.get("publish_date")
                or ""
            ),
            macro_regime_calendar_rows=macro_regime_calendar_rows,
        )
        extraction_quality["claim_component_roles"] = component_roles
        refreshed["claim_regime_trace"] = _build_claim_regime_trace(
            as_of_datetime=(
                refreshed.get("signal_datetime")
                or refreshed.get("publish_date")
                or ""
            ),
            target=target,
            component_roles=component_roles,
        )
        extraction_quality["claim_mechanism_roles"] = _infer_claim_mechanism_roles(
            claim_text,
            target=target,
            metric_proxy_mapping=metric_proxy_mapping,
        )
        mechanism_roles = _ensure_mapping(extraction_quality.get("claim_mechanism_roles"))
        mapping_gaps = _forecast_mapping_gaps(refreshed)
        if mapping_gaps:
            refreshed["forecast_testability"] = "insufficient_mapping"
            extraction_quality["mapping_gaps"] = mapping_gaps
            extraction_quality["needs_human_review"] = True
        else:
            extraction_quality.pop("mapping_gaps", None)
            if refreshed.get("forecast_testability") == "insufficient_mapping":
                refreshed["forecast_testability"] = "testable"
                extraction_quality["needs_human_review"] = False
        refreshed["extraction_quality"] = extraction_quality
        previous_pre_review = _ensure_mapping(refreshed.get("pre_review"))
        previous_from_llm = (
            previous_pre_review.get("decision_source") == "llm_financial_practitioner"
        )
        refreshed["pre_review"] = _forecast_claim_pre_review(
            refreshed,
            component_roles=component_roles,
            mechanism_roles=mechanism_roles,
            mapping_gaps=mapping_gaps,
            analyst_claim_adjusted=analyst_claim_adjusted,
            llm_decision=previous_pre_review.get("decision") if previous_from_llm else "",
            llm_reason=previous_pre_review.get("reason") if previous_from_llm else "",
        )
        refreshed_rows.append(refreshed)
    return _select_forecast_claims_per_report(refreshed_rows)


def _refresh_analytical_footprint_indicator_governance(
    footprint_rows: Sequence[Mapping[str, Any]],
    *,
    metadata_rows: Sequence[Mapping[str, Any]] = (),
    root_path: Path | None = None,
    chunk_chars: int = 60_000,
    max_chunks: int = 8,
) -> list[dict[str, Any]]:
    metadata_by_source = _source_report_metadata(metadata_rows) if metadata_rows else {}
    chunk_cache: dict[tuple[str, int], str] = {}
    seed_rule_match_cache: dict[
        tuple[str, int],
        tuple[TextGroundedSeedRuleMatch, ...],
    ] = {}
    refreshed_rows: list[dict[str, Any]] = []
    for row in footprint_rows:
        refreshed = dict(row)
        original_indicator_mentions = _normalize_indicator_mentions(
            refreshed.get("indicator_mentions")
        )
        base_indicator_mentions = [
            mention
            for mention in original_indicator_mentions
            if str(mention.get("inference_source") or "")
            not in INDICATOR_METADATA_DERIVED_INFERENCE_SOURCES
        ]
        indicator_mentions = list(original_indicator_mentions)
        text_grounded_mentions: list[dict[str, Any]] = []
        if metadata_by_source and root_path is not None:
            source_id = str(refreshed.get("source_id") or "")
            chunk_index = _footprint_markdown_chunk_index(refreshed)
            cache_key = (
                (source_id, chunk_index)
                if source_id and chunk_index is not None
                else None
            )
            if cache_key is not None and cache_key in chunk_cache:
                chunk = chunk_cache[cache_key]
            else:
                chunk = _footprint_markdown_chunk(
                    refreshed,
                    metadata_by_source=metadata_by_source,
                    root_path=root_path,
                    chunk_chars=chunk_chars,
                    max_chunks=max_chunks,
                )
                if cache_key is not None:
                    chunk_cache[cache_key] = chunk
            if cache_key is not None and cache_key in seed_rule_match_cache:
                seed_rule_matches = seed_rule_match_cache[cache_key]
            else:
                seed_rule_matches = _text_grounded_indicator_rule_matches(chunk)
                if cache_key is not None:
                    seed_rule_match_cache[cache_key] = seed_rule_matches
            text_grounded_mentions = _text_grounded_indicator_mentions(
                chunk,
                footprint_context=_footprint_indicator_context(refreshed),
                matched_seed_rules=seed_rule_matches,
            )
            if text_grounded_mentions:
                indicator_mentions = list(base_indicator_mentions)
            seen_canonicals = {
                str(mention.get("canonical_metric_candidate") or "")
                for mention in indicator_mentions
                if not _indicator_value_unknown(
                    mention.get("canonical_metric_candidate")
                )
            }
            indicator_mentions.extend(
                mention
                for mention in text_grounded_mentions
                if str(mention.get("canonical_metric_candidate") or "")
                not in seen_canonicals
            )
        has_complete_mapping = bool(indicator_mentions) and any(
            not _indicator_value_unknown(mention.get("canonical_metric_candidate"))
            and mention.get("source_grounded") is True
            for mention in indicator_mentions
        )
        if not has_complete_mapping:
            context_mentions = _context_seed_indicator_mentions(
                _footprint_indicator_context(refreshed)
            )
            seen_canonicals = {
                str(mention.get("canonical_metric_candidate") or "")
                for mention in indicator_mentions
                if not _indicator_value_unknown(
                    mention.get("canonical_metric_candidate")
                )
            }
            indicator_mentions.extend(
                mention
                for mention in context_mentions
                if str(mention.get("canonical_metric_candidate") or "")
                not in seen_canonicals
            )
        refreshed["indicator_mentions"] = _prioritize_indicator_mentions_for_review(
            indicator_mentions
        )
        refreshed_rows.append(refreshed)
    return refreshed_rows


def _normalize_footprints(
    payload: Mapping[str, Any],
    row: Mapping[str, Any],
    *,
    run_id: str,
    model: str,
    report_id: str,
    chunk_span_id: str,
    markdown_chunk: str = "",
) -> list[dict[str, Any]]:
    records: list[dict[str, Any]] = []
    for item in _ensure_list(payload.get("analytical_footprints")):
        footprint = _ensure_mapping(item)
        topic = _record_text(footprint, "topic", "name") or "unknown"
        target_agents, target_entities = _split_agent_and_entity_candidates(
            footprint.get("target_agent_candidates")
        )
        analysis_patterns = _ensure_list(footprint.get("analysis_patterns"))
        indicator_mentions = _normalize_indicator_mentions(
            footprint.get("indicator_mentions")
        )
        if not indicator_mentions:
            indicator_mentions = _text_grounded_indicator_mentions(
                markdown_chunk,
                footprint_context=_footprint_indicator_context(
                    {"topic": topic, "analysis_patterns": analysis_patterns}
                ),
            )
        if not indicator_mentions:
            indicator_mentions = _context_seed_indicator_mentions(
                _footprint_indicator_context(
                    {"topic": topic, "analysis_patterns": analysis_patterns}
                )
            )
        indicator_mentions = _prioritize_indicator_mentions_for_review(
            indicator_mentions
        )
        record = {
            "footprint_id": _stable_id(
                "AFP",
                {
                    "report_id": report_id,
                    "chunk_span_id": chunk_span_id,
                    "topic": topic,
                    "indicator_mentions": footprint.get("indicator_mentions"),
                },
            ),
            "report_id": report_id,
            "source_id": str(row.get("source_id") or ""),
            "source_span_ids": _source_span_ids(footprint, chunk_span_id),
            "extraction_type": str(footprint.get("extraction_type") or "mixed"),
            "market": "CN_A_SHARE",
            "sector": _report_sector_bucket(row),
            "topic": topic,
            "indicator_mentions": indicator_mentions,
            "analysis_patterns": analysis_patterns,
            "target_agent_candidates": target_agents,
            "target_entity_candidates": target_entities,
            "license_class": "operator_approved_internal_research_use",
            "storage_policy": "derived_metadata_only_full_text_cached_locally",
            "extractor": {
                "run_id": run_id,
                "model": model,
                "input_mode": "original_markdown",
            },
        }
        records.append(record)
    return records


def _bounded_metadata_text(value: Any, *, max_chars: int = MAX_STORED_CLAIM_TEXT_CHARS) -> str:
    normalized = re.sub(r"\s+", " ", str(value or "")).strip()
    if len(normalized) <= max_chars:
        return normalized
    return normalized[: max_chars - 3].rstrip() + "..."


def _footprint_review_target_hash(row: Mapping[str, Any]) -> str:
    payload = {
        "footprint_id": row.get("footprint_id"),
        "report_id": row.get("report_id"),
        "source_id": row.get("source_id"),
        "source_span_ids": _ensure_list(row.get("source_span_ids")),
        "extraction_type": row.get("extraction_type"),
        "topic": row.get("topic"),
        "indicator_mentions": row.get("indicator_mentions"),
        "analysis_patterns": row.get("analysis_patterns"),
    }
    encoded = json.dumps(
        _jsonable(payload),
        ensure_ascii=False,
        sort_keys=True,
        separators=(",", ":"),
    ).encode("utf-8")
    return "sha256:" + sha256(encoded).hexdigest()


def _indicator_review_preview(mentions: Any) -> list[dict[str, Any]]:
    preview: list[dict[str, Any]] = []
    for mention in _ensure_list(mentions)[:5]:
        mention_map = _ensure_mapping(mention)
        preview.append(
            {
                "indicator_text": _bounded_metadata_text(
                    mention_map.get("indicator_text")
                ),
                "canonical_metric_candidate": _bounded_metadata_text(
                    mention_map.get("canonical_metric_candidate")
                ),
                "data_source_mentioned": _bounded_metadata_text(
                    mention_map.get("data_source_mentioned")
                ),
                "frequency": _bounded_metadata_text(mention_map.get("frequency")),
                "transformation": _bounded_metadata_text(
                    mention_map.get("transformation")
                ),
                "source_grounded": bool(mention_map.get("source_grounded")),
            }
        )
    return preview


def _indicator_review_summary(mentions: Any, *, preview_limit: int = 5) -> dict[str, Any]:
    mention_maps = [
        _ensure_mapping(item)
        for item in _ensure_list(mentions)
        if isinstance(item, Mapping)
    ]
    unknown_count = 0
    ungrounded_count = 0
    complete_count = 0
    hidden_unknown_count = 0
    hidden_ungrounded_count = 0
    for index, mention in enumerate(mention_maps):
        canonical_unknown = _indicator_value_unknown(
            mention.get("canonical_metric_candidate")
        )
        source_ungrounded = mention.get("source_grounded") is not True
        if canonical_unknown:
            unknown_count += 1
            if index >= preview_limit:
                hidden_unknown_count += 1
        if source_ungrounded:
            ungrounded_count += 1
            if index >= preview_limit:
                hidden_ungrounded_count += 1
        if not canonical_unknown and not source_ungrounded:
            complete_count += 1
    mention_count = len(mention_maps)
    hidden_count = max(0, mention_count - preview_limit)
    all_mentions_complete = (
        bool(mention_maps) and unknown_count == 0 and ungrounded_count == 0
    )
    return {
        "mention_count": mention_count,
        "preview_count": min(mention_count, preview_limit),
        "preview_limit": preview_limit,
        "hidden_count": hidden_count,
        "unknown_canonical_count": unknown_count,
        "ungrounded_count": ungrounded_count,
        "complete_source_grounded_count": complete_count,
        "hidden_unknown_canonical_count": hidden_unknown_count,
        "hidden_ungrounded_count": hidden_ungrounded_count,
        "mapping_complete": all_mentions_complete,
    }


def _footprint_review_indicator_summary(row: Mapping[str, Any]) -> dict[str, Any]:
    summary = _ensure_mapping(row.get("indicator_mentions_review_summary"))
    if type(summary.get("mention_count")) is int:
        out = dict(summary)
        out.setdefault("summary_source", "indicator_mentions_review_summary")
        return out
    fallback = _indicator_review_summary(row.get("indicator_mentions_review_preview"))
    fallback["summary_source"] = "indicator_mentions_review_preview"
    return fallback


ANALYTICAL_FOOTPRINT_REVIEW_PATTERN_PREVIEW_TEXT_KEYS = (
    "pattern_candidate",
    "pattern_name",
    "pattern",
    "name",
    "description",
    "step",
)

ANALYTICAL_FOOTPRINT_REVIEW_PATTERN_PREVIEW_FORBIDDEN_KEYS = {
    "raw_text",
    "source_span",
    "source_span_text",
    "source_text",
}


def _analysis_pattern_review_preview_text(pattern: Mapping[str, Any]) -> str:
    text = _record_text(pattern, *ANALYTICAL_FOOTPRINT_REVIEW_PATTERN_PREVIEW_TEXT_KEYS)
    if text:
        return text
    steps = tuple(
        _bounded_metadata_text(step, max_chars=120)
        for step in _ensure_list(pattern.get("steps"))[:3]
        if str(step or "").strip()
    )
    if steps:
        return " / ".join(steps)
    safe_pattern = {
        str(key): value
        for key, value in pattern.items()
        if str(key) not in ANALYTICAL_FOOTPRINT_REVIEW_PATTERN_PREVIEW_FORBIDDEN_KEYS
        and not str(key).endswith("_text")
    }
    if safe_pattern:
        return json.dumps(_jsonable(safe_pattern), ensure_ascii=False, sort_keys=True)
    return ""


def _analysis_pattern_review_preview(patterns: Any) -> list[str]:
    out: list[str] = []
    for pattern in _ensure_list(patterns)[:5]:
        if isinstance(pattern, Mapping):
            text = _analysis_pattern_review_preview_text(pattern)
        else:
            text = str(pattern or "")
        if text:
            out.append(_bounded_metadata_text(text))
    return out


def _existing_footprint_review_rows(path: Path) -> dict[str, Mapping[str, Any]]:
    if not path.exists():
        return {}
    rows, _ = load_jsonl_with_errors(path, label="analytical footprint review")
    return {
        str(row.get("footprint_id") or ""): row
        for row in rows
        if isinstance(row, Mapping) and str(row.get("footprint_id") or "").strip()
    }


def _footprint_review_template_row(
    row: Mapping[str, Any],
    *,
    existing_row: Mapping[str, Any] | None = None,
) -> dict[str, Any]:
    target_hash = _footprint_review_target_hash(row)
    review_row = {
        "review_kind": "analytical_footprint_gold_set",
        "footprint_id": str(row.get("footprint_id") or ""),
        "report_id": str(row.get("report_id") or ""),
        "source_id": str(row.get("source_id") or ""),
        "source_span_ids": _ensure_list(row.get("source_span_ids")),
        "target_row_hash": target_hash,
        "target_review_path": ANALYTICAL_FOOTPRINT_REVIEW_TEMPLATE_PATH,
        "review_context_ref": "registry/report_intelligence/analytical_footprints.jsonl",
        "manual_review_required": True,
        "topic_preview": _bounded_metadata_text(row.get("topic")),
        "extraction_type": str(row.get("extraction_type") or "unknown"),
        "sector": str(row.get("sector") or "unknown"),
        "indicator_mentions_review_preview": _indicator_review_preview(
            row.get("indicator_mentions")
        ),
        "indicator_mentions_review_summary": _indicator_review_summary(
            row.get("indicator_mentions")
        ),
        "analysis_patterns_review_preview": _analysis_pattern_review_preview(
            row.get("analysis_patterns")
        ),
        "target_agent_candidates": _ensure_list(row.get("target_agent_candidates")),
        "target_entity_candidates": _ensure_list(row.get("target_entity_candidates")),
        "footprint_correct": None,
        "source_span_supports_footprint": None,
        "metric_mapping_correct": None,
        "inferred_steps_tagged_correctly": None,
        "unknowns_used_when_uncertain": None,
        "no_proprietary_text_leakage": None,
        "manual_error_tags": [],
        "reviewer": "",
        "review_date": "",
        "review_notes": "",
    }
    if (
        existing_row
        and existing_row.get("target_row_hash") == target_hash
        and str(existing_row.get("review_kind") or "")
        == "analytical_footprint_gold_set"
    ):
        for field in (
            *ANALYTICAL_FOOTPRINT_REVIEW_REQUIRED_FIELDS,
            "manual_error_tags",
        ):
            if field in existing_row:
                review_row[field] = existing_row[field]
    return review_row


def build_analytical_footprint_review_rows(
    footprint_rows: Sequence[Mapping[str, Any]],
    *,
    existing_template_path: Path | None = None,
) -> list[dict[str, Any]]:
    existing_rows = (
        _existing_footprint_review_rows(existing_template_path)
        if existing_template_path is not None
        else {}
    )
    return [
        _footprint_review_template_row(
            row,
            existing_row=existing_rows.get(str(row.get("footprint_id") or "")),
        )
        for row in footprint_rows
        if str(row.get("footprint_id") or "").strip()
    ]


def _footprint_review_row_complete(row: Mapping[str, Any]) -> bool:
    if not str(row.get("reviewer") or "").strip():
        return False
    if not str(row.get("review_date") or "").strip():
        return False
    if not str(row.get("review_notes") or "").strip():
        return False
    return all(
        isinstance(row.get(field), bool)
        for field in ANALYTICAL_FOOTPRINT_REVIEW_BOOLEAN_FIELDS
    )


_ANALYTICAL_FOOTPRINT_REVIEW_FIELD_BY_METRIC = {
    "footprint_precision": "footprint_correct",
    "span_support_precision": "source_span_supports_footprint",
    "metric_mapping_accuracy": "metric_mapping_correct",
    "inferred_step_tagging_accuracy": "inferred_steps_tagged_correctly",
    "unknown_on_ambiguity_rate": "unknowns_used_when_uncertain",
    "proprietary_leakage_free_rate": "no_proprietary_text_leakage",
}


def _analytical_footprint_quality_metric_rows(
    metric: str, complete_rows: Sequence[Mapping[str, Any]]
) -> list[Mapping[str, Any]]:
    if metric == "metric_mapping_accuracy":
        return [row for row in complete_rows if row.get("footprint_correct") is True]
    return list(complete_rows)


def _analytical_footprint_quality_gap_targets(
    complete_rows: Sequence[Mapping[str, Any]],
    precision_recall_report: Mapping[str, Any],
) -> Mapping[str, Any] | None:
    complete_denominator = len(complete_rows)
    if complete_denominator == 0:
        return None
    metric_targets: dict[str, Mapping[str, Any]] = {}
    active_gap_count = 0
    for metric, threshold in ANALYTICAL_FOOTPRINT_REVIEW_QUALITY_THRESHOLDS.items():
        field = _ANALYTICAL_FOOTPRINT_REVIEW_FIELD_BY_METRIC[metric]
        metric_rows = _analytical_footprint_quality_metric_rows(metric, complete_rows)
        denominator = len(metric_rows)
        current_rate = precision_recall_report.get(metric)
        current_pass_count = sum(row.get(field) is True for row in metric_rows)
        required_pass_count = ceil((threshold * denominator) - 1e-12)
        minimum_gap_count = max(0, required_pass_count - current_pass_count)
        if minimum_gap_count:
            active_gap_count += 1
        metric_targets[metric] = {
            "operator": ">=",
            "threshold": threshold,
            "current_rate": current_rate,
            "denominator": denominator,
            "denominator_policy": (
                "footprint_correct_true_rows"
                if metric == "metric_mapping_accuracy"
                else "completed_review_rows"
            ),
            "current_pass_count": current_pass_count,
            "required_pass_count": required_pass_count,
            "minimum_additional_pass_count_if_denominator_unchanged": minimum_gap_count,
            "is_passing": minimum_gap_count == 0,
        }
    return {
        "policy": (
            "public_safe_aggregate_quality_gate_gap_targets_no_source_text"
        ),
        "interpretation": (
            "count deltas are computed over each metric denominator; metric "
            "mapping is evaluated only on footprint_correct=true rows so rejected "
            "footprints are not double-counted as mapping failures"
        ),
        "sample_size_completed_rows": {
            "current_count": complete_denominator,
            "pending_rows_are_excluded_from_metric_denominator": True,
        },
        "metrics": metric_targets,
        "active_gap_count": active_gap_count,
    }


def _review_bool(value: Any) -> bool | None:
    if isinstance(value, bool):
        return value
    if isinstance(value, str):
        normalized = value.strip().lower()
        if normalized in {"true", "yes", "y", "1", "pass", "passed"}:
            return True
        if normalized in {"false", "no", "n", "0", "fail", "failed"}:
            return False
    return None


def _negative_example_bool(
    row: Mapping[str, Any],
    keys: Sequence[str],
) -> bool | None:
    for key in keys:
        if key in row:
            parsed = _review_bool(row.get(key))
            if parsed is not None:
                return parsed
    return None


def _analytical_footprint_negative_recall_report(
    negative_example_rows: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    completed_rows = []
    positive_rows = []
    recovered_rows = []
    for row in negative_example_rows:
        expected = _negative_example_bool(
            row,
            (
                "expected_footprint_present",
                "should_have_footprint",
                "reusable_footprint_present",
                "human_expected_footprint",
            ),
        )
        recovered = _negative_example_bool(
            row,
            (
                "extracted_footprint_found",
                "matched_existing_footprint",
                "covered_by_extraction",
                "extractor_found_footprint",
            ),
        )
        if expected is None or recovered is None:
            continue
        completed_rows.append(row)
        if expected:
            positive_rows.append(row)
            if recovered:
                recovered_rows.append(row)

    if not negative_example_rows:
        recall_estimate = None
        recall_status = "requires_human_negative_examples"
    elif not completed_rows:
        recall_estimate = None
        recall_status = "negative_examples_incomplete"
    elif not positive_rows:
        recall_estimate = None
        recall_status = "no_positive_negative_examples"
    else:
        recall_estimate = round(len(recovered_rows) / len(positive_rows), 6)
        recall_status = "computed_from_human_negative_examples"
    return {
        "recall_estimate": recall_estimate,
        "recall_status": recall_status,
        "negative_example_sample_count": len(negative_example_rows),
        "negative_example_completed_count": len(completed_rows),
        "negative_example_positive_count": len(positive_rows),
        "negative_example_true_positive_count": len(recovered_rows),
        "negative_example_false_negative_count": max(
            0,
            len(positive_rows) - len(recovered_rows),
        ),
        "negative_example_policy": (
            "recall uses private human-reviewed negative examples; public "
            "summary stores aggregate counts only"
        ),
    }


def _read_analytical_footprint_negative_examples(
    registry_dir: Path,
) -> list[Mapping[str, Any]]:
    path = registry_dir / "analytical_footprint_negative_examples.jsonl"
    if not path.exists():
        return []
    rows, _errors = load_jsonl_with_errors(
        path,
        label="analytical_footprint_negative_examples",
    )
    return [row for row in rows if isinstance(row, Mapping)]


def _negative_example_source_text_included(row: Mapping[str, Any]) -> bool:
    value = row.get("source_text_included")
    parsed = _review_bool(value)
    if parsed is not None:
        return parsed
    if isinstance(value, str):
        return bool(value.strip())
    return bool(value)


def build_analytical_footprint_negative_example_progress(
    root: str | Path,
    input_path: str | Path = ANALYTICAL_FOOTPRINT_NEGATIVE_EXAMPLES_PATH,
    *,
    minimum_sample_target: int = 200,
    expected_positive_minimum_target: int = 50,
) -> AnalyticalFootprintNegativeExampleProgressReport:
    root_path = Path(root)
    resolved_input_path = Path(input_path)
    if not resolved_input_path.is_absolute():
        resolved_input_path = root_path / resolved_input_path

    blockers: list[str] = []
    rows: list[Mapping[str, Any]] = []
    if not resolved_input_path.exists():
        blockers.append(f"input_path is missing: {resolved_input_path}")
    else:
        raw_rows, parse_blockers = load_jsonl_with_errors(
            resolved_input_path,
            label="analytical_footprint_negative_examples",
        )
        rows, invalid_rows = _split_mapping_rows(raw_rows)
        blockers.extend(parse_blockers)
        if invalid_rows:
            blockers.append(
                "analytical_footprint_negative_examples row must be object at "
                "row(s): " + ", ".join(str(row_number) for row_number in invalid_rows)
            )

    recall = _analytical_footprint_negative_recall_report(rows)
    pending_required_fields = _negative_example_pending_required_fields(rows)
    source_text_included_count = sum(
        1 for row in rows if _negative_example_source_text_included(row)
    )
    sample_count = int(recall["negative_example_sample_count"])
    completed_count = int(recall["negative_example_completed_count"])
    positive_count = int(recall["negative_example_positive_count"])
    expected_positive_remaining = max(
        0,
        int(expected_positive_minimum_target) - positive_count,
    )

    if sample_count < int(minimum_sample_target):
        blockers.append(
            "negative_example_sample_count below target: "
            f"{sample_count} < {int(minimum_sample_target)}"
        )
    if completed_count < sample_count:
        blockers.append(
            "negative examples need human decisions for expected_footprint_present "
            f"and extracted_footprint_found: {completed_count}/{sample_count}"
        )
    if pending_required_fields:
        blockers.append(
            "negative examples have pending required human-review fields: "
            + ", ".join(
                f"{field}={count}"
                for field, count in sorted(pending_required_fields.items())
            )
        )
    if positive_count < int(expected_positive_minimum_target):
        blockers.append(
            "negative_example_positive_count below target: "
            f"{positive_count} < {int(expected_positive_minimum_target)}"
        )
    if recall["recall_status"] != "computed_from_human_negative_examples":
        blockers.append(
            "recall_status is not computed_from_human_negative_examples: "
            f"{recall['recall_status']}"
        )
    if source_text_included_count:
        blockers.append(
            "negative examples must not include source text: "
            f"{source_text_included_count} row(s)"
        )

    return AnalyticalFootprintNegativeExampleProgressReport(
        report_id=(
            "RKE-REPORT-INTELLIGENCE-FOOTPRINT-NEGATIVE-EXAMPLE-PROGRESS-REPORT"
        ),
        input_path=str(resolved_input_path),
        accepted=not blockers,
        recall_status=str(recall["recall_status"]),
        recall_estimate=recall["recall_estimate"],
        minimum_sample_target=int(minimum_sample_target),
        sample_count=sample_count,
        completed_count=completed_count,
        positive_count=positive_count,
        true_positive_count=int(recall["negative_example_true_positive_count"]),
        false_negative_count=int(recall["negative_example_false_negative_count"]),
        expected_positive_minimum_target=int(expected_positive_minimum_target),
        expected_positive_remaining=expected_positive_remaining,
        source_text_included_count=source_text_included_count,
        pending_required_fields=pending_required_fields,
        blockers=tuple(blockers),
        policy=str(recall["negative_example_policy"]),
    )


def build_analytical_footprint_review_summary(
    review_rows: Sequence[Mapping[str, Any]],
    *,
    negative_example_rows: Sequence[Mapping[str, Any]] = (),
) -> dict[str, Any]:
    complete_rows = [row for row in review_rows if _footprint_review_row_complete(row)]
    pending_rows = len(review_rows) - len(complete_rows)

    def rate(field: str, *, metric: str | None = None) -> float | None:
        denominator_rows = (
            _analytical_footprint_quality_metric_rows(metric, complete_rows)
            if metric is not None
            else complete_rows
        )
        if not denominator_rows:
            return None
        return round(
            sum(1 for row in denominator_rows if row.get(field) is True)
            / len(denominator_rows),
            6,
        )

    error_counts: dict[str, int] = {}
    for row in complete_rows:
        for tag in _ensure_list(row.get("manual_error_tags")):
            tag_text = str(tag or "").strip()
            if tag_text:
                error_counts[tag_text] = error_counts.get(tag_text, 0) + 1
    blockers: list[str] = []
    if not review_rows:
        blockers.append("analytical footprint review template has no rows")
    if pending_rows:
        blockers.append(
            f"{pending_rows} analytical footprint review rows still pending"
        )
    precision_recall_report = {
        "footprint_precision": rate("footprint_correct"),
        "span_support_precision": rate("source_span_supports_footprint"),
        "metric_mapping_accuracy": rate(
            "metric_mapping_correct", metric="metric_mapping_accuracy"
        ),
        "inferred_step_tagging_accuracy": rate(
            "inferred_steps_tagged_correctly"
        ),
        "unknown_on_ambiguity_rate": rate("unknowns_used_when_uncertain"),
        "proprietary_leakage_free_rate": rate(
            "no_proprietary_text_leakage"
        ),
        **_analytical_footprint_negative_recall_report(negative_example_rows),
    }
    quality_gap_targets = _analytical_footprint_quality_gap_targets(
        complete_rows,
        precision_recall_report,
    )
    quality_gate_blockers: list[str] = []
    for field, threshold in ANALYTICAL_FOOTPRINT_REVIEW_QUALITY_THRESHOLDS.items():
        value = precision_recall_report.get(field)
        if value is None:
            quality_gate_blockers.append(f"{field} unavailable")
        elif float(value) < threshold:
            quality_gate_blockers.append(
                f"{field} {value:.6f} below threshold {threshold:.2f}"
            )
    review_complete = bool(review_rows) and pending_rows == 0
    quality_gate_passed = review_complete and not quality_gate_blockers
    return {
        "summary_id": "RKE-REPORT-INTELLIGENCE-FOOTPRINT-REVIEW-SUMMARY",
        "review_kind": "analytical_footprint_gold_set",
        "accepted": quality_gate_passed,
        "review_complete": review_complete,
        "quality_gate_passed": quality_gate_passed,
        "quality_gate_thresholds": dict(
            sorted(ANALYTICAL_FOOTPRINT_REVIEW_QUALITY_THRESHOLDS.items())
        ),
        "quality_gap_targets": quality_gap_targets,
        "quality_gate_blockers": quality_gate_blockers,
        "manual_review_required": True,
        "review_template_path": ANALYTICAL_FOOTPRINT_REVIEW_TEMPLATE_PATH,
        "error_taxonomy_path": ANALYTICAL_FOOTPRINT_ERROR_TAXONOMY_PATH,
        "total_rows": len(review_rows),
        "complete_rows": len(complete_rows),
        "pending_rows": pending_rows,
        "precision_recall_report": precision_recall_report,
        "error_counts": dict(sorted(error_counts.items())),
        "blockers": [*blockers, *quality_gate_blockers],
        "policy": (
            "analytical footprint review is a manual gold-set gate for source "
            "grounding, metric mapping, inferred-step tagging, ambiguity handling, "
            "and proprietary text leakage; no rows are accepted until reviewers fill "
            "all required fields and quality thresholds pass"
        ),
    }


def build_analytical_footprint_error_taxonomy() -> dict[str, Any]:
    return {
        "taxonomy_id": "RKE-REPORT-INTELLIGENCE-FOOTPRINT-ERROR-TAXONOMY",
        "review_kind": "analytical_footprint_gold_set",
        "required_manual_fields": list(
            ANALYTICAL_FOOTPRINT_REVIEW_REQUIRED_FIELDS
        )
        + ["manual_error_tags"],
        "error_tags": [
            {
                "tag": "unsupported_footprint",
                "description": "The extracted topic or method is not supported by the cited span.",
            },
            {
                "tag": "metric_mapping_error",
                "description": "The canonical metric, unit, source, frequency, or transformation is wrong.",
            },
            {
                "tag": "hallucinated_metric",
                "description": "The extractor invented a metric not present in the report or cited span.",
            },
            {
                "tag": "inferred_step_mislabeled_source_grounded",
                "description": "A derived or LLM-inferred step was stored as source-grounded.",
            },
            {
                "tag": "ambiguous_metric_not_unknown",
                "description": "An uncertain metric/source/window should have been marked unknown.",
            },
            {
                "tag": "proprietary_text_leakage",
                "description": "The review row includes long proprietary report text instead of metadata.",
            },
        ],
    }


def write_analytical_footprint_review_artifacts(
    registry_dir: Path,
    footprint_rows: Sequence[Mapping[str, Any]],
    *,
    preserve_existing_summary: bool = False,
) -> dict[str, str]:
    template_path = registry_dir / "analytical_footprint_review_template.jsonl"
    summary_path = registry_dir / "analytical_footprint_review_summary.json"
    taxonomy_path = registry_dir / "analytical_footprint_error_taxonomy.json"
    review_rows = build_analytical_footprint_review_rows(
        footprint_rows,
        existing_template_path=template_path,
    )
    summary = build_analytical_footprint_review_summary(
        review_rows,
        negative_example_rows=_read_analytical_footprint_negative_examples(
            registry_dir
        ),
    )
    taxonomy = build_analytical_footprint_error_taxonomy()
    preserve_summary = preserve_existing_summary and summary_path.exists() and not review_rows
    if preserve_summary:
        summary_output = {"path": summary_path}
    else:
        summary_output = _write_json(summary_path, summary)
    if preserve_existing_summary and taxonomy_path.exists():
        taxonomy_output = {"path": taxonomy_path}
    else:
        taxonomy_output = _write_json(taxonomy_path, taxonomy)
    return {
        "analytical_footprint_review_template": str(
            _write_jsonl(template_path, review_rows)["path"]
        ),
        "analytical_footprint_review_summary": str(
            summary_output["path"]
        ),
        "analytical_footprint_error_taxonomy": str(
            taxonomy_output["path"]
        ),
    }


def _footprint_review_pending_required_fields(
    review_rows: Sequence[Mapping[str, Any]],
) -> dict[str, int]:
    counts: dict[str, int] = {}
    for row in review_rows:
        for field in ANALYTICAL_FOOTPRINT_REVIEW_BOOLEAN_FIELDS:
            if not isinstance(row.get(field), bool):
                counts[field] = counts.get(field, 0) + 1
        for field in ("reviewer", "review_date", "review_notes"):
            if not str(row.get(field) or "").strip():
                counts[field] = counts.get(field, 0) + 1
    return dict(sorted(counts.items()))


def _manual_review_backup_path(root_path: Path, source_path: Path) -> Path:
    try:
        relative = source_path.resolve().relative_to(root_path.resolve())
        label = "__".join(relative.parts)
    except ValueError:
        label = source_path.name
    safe_label = re.sub(r"[^A-Za-z0-9._-]+", "_", label)
    timestamp = re.sub(r"[^0-9A-Za-z]+", "", _utc_now())
    return rke_tmp_root() / "review-backups" / f"{timestamp}_{safe_label}"


def prepare_analytical_footprint_review_import(
    root: str | Path,
    output_path: str | Path = ANALYTICAL_FOOTPRINT_REVIEWED_IMPORT_PATH,
    *,
    reviewer: str = "",
    review_date: str = "",
    limit: int | None = None,
    offset: int = 0,
    overwrite: bool = False,
    priority: bool = False,
    quality_gap_only: bool = False,
) -> AnalyticalFootprintReviewPrepareReport:
    root_path = Path(root)
    target_path = root_path / ANALYTICAL_FOOTPRINT_REVIEW_TEMPLATE_PATH
    resolved_output_path = Path(output_path)
    if not resolved_output_path.is_absolute():
        resolved_output_path = root_path / resolved_output_path
    target_rows_raw, target_parse_blockers = load_jsonl_with_errors(
        target_path,
        label="analytical footprint target review",
    )
    target_rows, invalid_target_rows = _split_mapping_rows(target_rows_raw)
    blockers: list[str] = []
    if not target_rows_raw:
        blockers.append("analytical footprint review template is empty")
    if invalid_target_rows:
        blockers.append(
            "analytical footprint target review row must be object at row(s): "
            + ", ".join(str(row_number) for row_number in invalid_target_rows)
        )
    blockers.extend(target_parse_blockers)
    if resolved_output_path.exists() and not overwrite:
        blockers.append(f"output_path already exists: {resolved_output_path}")
    offset_value = max(0, int(offset))
    limit_value = None if limit is None else max(0, int(limit))
    existing_output_ids: set[str] = set()
    if quality_gap_only and overwrite and resolved_output_path.exists():
        existing_output_rows, _ = load_jsonl_with_errors(
            resolved_output_path,
            label="existing analytical footprint review output",
        )
        existing_output_ids = {
            str(row.get("footprint_id") or "")
            for row in existing_output_rows
            if isinstance(row, Mapping) and str(row.get("footprint_id") or "").strip()
        }
    if quality_gap_only:
        selected_indexed_rows = [
            (index, row)
            for index, row in enumerate(target_rows)
            if _footprint_review_row_complete(row)
            and row.get("footprint_correct") is True
            and str(row.get("footprint_id") or "") not in existing_output_ids
            and any(
                row.get(field) is False
                for field in ANALYTICAL_FOOTPRINT_REVIEW_BOOLEAN_FIELDS
            )
        ]
        if priority:
            selected_indexed_rows = sorted(
                selected_indexed_rows,
                key=lambda item: (-_footprint_review_priority_score(item[1]), item[0]),
            )
        selected_indexed_rows = selected_indexed_rows[
            offset_value : None if limit_value is None else offset_value + limit_value
        ]
        selected_target_rows = [row for _, row in selected_indexed_rows]
        selection_policy = (
            "quality_gap_priority_sorted" if priority else "quality_gap_target_order"
        )
    elif priority:
        pending_indexed_rows = [
            (index, row)
            for index, row in enumerate(target_rows)
            if not _footprint_review_row_complete(row)
        ]
        prioritized_rows = sorted(
            pending_indexed_rows,
            key=lambda item: (-_footprint_review_priority_score(item[1]), item[0]),
        )
        selected_indexed_rows = prioritized_rows[
            offset_value : None if limit_value is None else offset_value + limit_value
        ]
        selected_target_rows = [row for _, row in selected_indexed_rows]
        selection_policy = "priority_sorted_pending"
    elif limit_value is None:
        selected_target_rows = target_rows[offset_value:] if offset_value else target_rows
        selection_policy = "target_order"
    else:
        pending_target_rows = [
            row for row in target_rows if not _footprint_review_row_complete(row)
        ]
        selected_target_rows = pending_target_rows[
            offset_value : offset_value + limit_value
        ]
        selection_policy = "pending_offset"
    scaffold_rows: list[dict[str, Any]] = []
    for row in selected_target_rows:
        scaffold = dict(row)
        if reviewer:
            scaffold["reviewer"] = reviewer
        if review_date:
            scaffold["review_date"] = review_date
        forbidden_paths = manual_review_forbidden_field_paths(scaffold)
        if forbidden_paths:
            blockers.append(
                "analytical footprint review scaffold contains forbidden fields: "
                + ", ".join(forbidden_paths)
            )
        scaffold_rows.append(scaffold)
    backup_path = ""
    backed_up_existing_output = False
    if not blockers:
        if overwrite and resolved_output_path.exists():
            backup = _manual_review_backup_path(root_path, resolved_output_path)
            backup.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(resolved_output_path, backup)
            backup_path = str(backup)
            backed_up_existing_output = True
        _write_jsonl(resolved_output_path, scaffold_rows)
    complete_rows = sum(1 for row in scaffold_rows if _footprint_review_row_complete(row))
    priority_score_counts = Counter(
        str(_footprint_review_priority_score(row)) for row in scaffold_rows
    )
    priority_reason_counts = Counter(
        reason
        for row in scaffold_rows
        for reason in _footprint_review_priority_reasons(row)
    )
    report = AnalyticalFootprintReviewPrepareReport(
        report_id="RKE-REPORT-INTELLIGENCE-FOOTPRINT-REVIEW-PREPARE-REPORT",
        target_path=ANALYTICAL_FOOTPRINT_REVIEW_TEMPLATE_PATH,
        output_path=str(resolved_output_path),
        accepted=not blockers,
        overwrite=overwrite,
        requested_limit=limit_value,
        requested_offset=offset_value,
        priority=bool(priority),
        selection_policy=selection_policy,
        output_rows=len(scaffold_rows),
        complete_rows=complete_rows,
        pending_rows=len(scaffold_rows) - complete_rows,
        pending_required_fields=_footprint_review_pending_required_fields(
            scaffold_rows
        ),
        selected_priority_score_counts=dict(sorted(priority_score_counts.items())),
        selected_priority_reason_counts=dict(sorted(priority_reason_counts.items())),
        blockers=tuple(blockers),
        backed_up_existing_output=backed_up_existing_output,
        backup_path=backup_path,
    )
    return report


def _negative_example_pending_required_fields(
    rows: Sequence[Mapping[str, Any]],
) -> dict[str, int]:
    fields = (
        "expected_footprint_present",
        "extracted_footprint_found",
        "reviewer",
        "review_date",
        "review_notes",
    )
    counts: dict[str, int] = {}
    for row in rows:
        for field in fields:
            value = row.get(field)
            if field in {"expected_footprint_present", "extracted_footprint_found"}:
                if _negative_example_bool(row, (field,)) is None:
                    counts[field] = counts.get(field, 0) + 1
            elif not str(value or "").strip():
                counts[field] = counts.get(field, 0) + 1
    return dict(sorted(counts.items()))


def _footprint_negative_example_target_hash(row: Mapping[str, Any]) -> str:
    payload = {
        "source_id": str(row.get("source_id") or ""),
        "report_id": str(row.get("report_id") or ""),
        "review_context_ref": str(row.get("review_context_ref") or ""),
        "sample_kind": str(row.get("sample_kind") or ""),
    }
    encoded = json.dumps(
        payload, ensure_ascii=False, sort_keys=True, separators=(",", ":")
    ).encode("utf-8")
    return "sha256:" + sha256(encoded).hexdigest()


def _negative_example_focus(
    *,
    forecast_claim_count: int,
    extracted_footprint_count: int,
) -> str:
    if forecast_claim_count > 0 and extracted_footprint_count == 0:
        return "claims_without_extracted_footprints"
    if extracted_footprint_count == 0:
        return "no_extracted_footprints"
    if forecast_claim_count > 0:
        return "claims_with_extracted_footprints"
    return "metadata_baseline"


def prepare_analytical_footprint_negative_examples(
    root: str | Path,
    output_path: str | Path = ANALYTICAL_FOOTPRINT_NEGATIVE_EXAMPLES_PATH,
    *,
    limit: int = 200,
    offset: int = 0,
    overwrite: bool = False,
) -> AnalyticalFootprintNegativeExamplePrepareReport:
    root_path = Path(root)
    registry_dir = root_path / "registry/report_intelligence"
    resolved_output_path = Path(output_path)
    if not resolved_output_path.is_absolute():
        resolved_output_path = root_path / resolved_output_path

    blockers: list[str] = []
    metadata_path = registry_dir / "report_metadata.jsonl"
    metadata_rows_raw, metadata_parse_blockers = load_jsonl_with_errors(
        metadata_path,
        label="report_metadata",
    )
    metadata_rows, invalid_metadata_rows = _split_mapping_rows(metadata_rows_raw)
    blockers.extend(metadata_parse_blockers)
    if invalid_metadata_rows:
        blockers.append(
            "report_metadata row must be object at row(s): "
            + ", ".join(str(row_number) for row_number in invalid_metadata_rows)
        )
    if not metadata_rows:
        blockers.append("report_metadata is missing or empty")

    forecast_claim_rows: list[Mapping[str, Any]] = []
    forecast_claim_path = registry_dir / "forecast_claims.jsonl"
    if forecast_claim_path.exists():
        rows_raw, parse_blockers = load_jsonl_with_errors(
            forecast_claim_path,
            label="forecast_claims",
        )
        forecast_claim_rows, invalid_rows = _split_mapping_rows(rows_raw)
        blockers.extend(parse_blockers)
        if invalid_rows:
            blockers.append(
                "forecast_claims row must be object at row(s): "
                + ", ".join(str(row_number) for row_number in invalid_rows)
            )

    footprint_rows: list[Mapping[str, Any]] = []
    footprint_path = registry_dir / "analytical_footprints.jsonl"
    if footprint_path.exists():
        rows_raw, parse_blockers = load_jsonl_with_errors(
            footprint_path,
            label="analytical_footprints",
        )
        footprint_rows, invalid_rows = _split_mapping_rows(rows_raw)
        blockers.extend(parse_blockers)
        if invalid_rows:
            blockers.append(
                "analytical_footprints row must be object at row(s): "
                + ", ".join(str(row_number) for row_number in invalid_rows)
            )

    if resolved_output_path.exists() and not overwrite:
        blockers.append(f"output_path already exists: {resolved_output_path}")

    claim_counts = Counter(
        str(row.get("source_id") or "")
        for row in forecast_claim_rows
        if str(row.get("source_id") or "").strip()
    )
    footprint_counts = Counter(
        str(row.get("source_id") or "")
        for row in footprint_rows
        if str(row.get("source_id") or "").strip()
    )

    candidates: list[tuple[int, str, dict[str, Any]]] = []
    seen_source_ids: set[str] = set()
    for row in metadata_rows:
        source_id = str(row.get("source_id") or "").strip()
        if not source_id or source_id in seen_source_ids:
            continue
        seen_source_ids.add(source_id)
        forecast_claim_count = int(claim_counts.get(source_id, 0))
        extracted_footprint_count = int(footprint_counts.get(source_id, 0))
        focus = _negative_example_focus(
            forecast_claim_count=forecast_claim_count,
            extracted_footprint_count=extracted_footprint_count,
        )
        priority_score = (
            (4 if focus == "claims_without_extracted_footprints" else 0)
            + (2 if focus == "no_extracted_footprints" else 0)
            + (1 if forecast_claim_count > 0 else 0)
        )
        report_id = str(row.get("report_id") or "")
        scaffold = {
            "negative_example_id": _stable_id(
                "AFNEG",
                {
                    "source_id": source_id,
                    "report_id": report_id,
                    "sample_kind": "report_level_footprint_recall_candidate",
                },
            ),
            "source_id": source_id,
            "report_id": report_id,
            "sample_kind": "report_level_footprint_recall_candidate",
            "review_context_ref": (
                "registry/report_intelligence/report_metadata.jsonl#"
                f"{source_id}"
            ),
            "report_type": str(row.get("report_type") or ""),
            "sector": str(row.get("sector") or ""),
            "publish_date": str(row.get("publish_date") or ""),
            "forecast_claim_count": forecast_claim_count,
            "extracted_footprint_count": extracted_footprint_count,
            "suggested_review_focus": focus,
            "priority_score": priority_score,
            "expected_footprint_present": None,
            "extracted_footprint_found": None,
            "reviewer": "",
            "review_date": "",
            "review_notes": "",
            "source_text_included": False,
            "human_review_required": True,
            "policy": (
                "private human-reviewed negative example scaffold for analytical "
                "footprint recall; fill expected_footprint_present and "
                "extracted_footprint_found only after human inspection"
            ),
        }
        scaffold["target_row_hash"] = _footprint_negative_example_target_hash(scaffold)
        candidates.append((priority_score, source_id, scaffold))

    selected_rows = [
        row
        for _score, _source_id, row in sorted(
            candidates,
            key=lambda item: (-item[0], item[1]),
        )[max(0, int(offset)) : max(0, int(offset)) + max(0, int(limit))]
    ]
    backup_path = ""
    backed_up_existing_output = False
    if not blockers:
        if overwrite and resolved_output_path.exists():
            backup = _manual_review_backup_path(root_path, resolved_output_path)
            backup.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(resolved_output_path, backup)
            backup_path = str(backup)
            backed_up_existing_output = True
        _write_jsonl(resolved_output_path, selected_rows)

    pending_required_fields = _negative_example_pending_required_fields(selected_rows)
    selected_focus_counts = Counter(
        str(row.get("suggested_review_focus") or "") for row in selected_rows
    )
    return AnalyticalFootprintNegativeExamplePrepareReport(
        report_id=(
            "RKE-REPORT-INTELLIGENCE-FOOTPRINT-NEGATIVE-EXAMPLE-PREPARE-REPORT"
        ),
        output_path=str(resolved_output_path),
        accepted=not blockers,
        overwrite=overwrite,
        requested_limit=max(0, int(limit)),
        requested_offset=max(0, int(offset)),
        output_rows=len(selected_rows),
        pending_rows=sum(
            1
            for row in selected_rows
            if _negative_example_bool(row, ("expected_footprint_present",)) is None
            or _negative_example_bool(row, ("extracted_footprint_found",)) is None
        ),
        pending_required_fields=pending_required_fields,
        expected_positive_minimum_target=50,
        selection_policy="priority_sorted_report_level_candidates",
        selected_focus_counts=dict(sorted(selected_focus_counts.items())),
        blockers=tuple(blockers),
        backed_up_existing_output=backed_up_existing_output,
        backup_path=backup_path,
    )


def _review_assist_preview(value: Any, *, max_chars: int = 96) -> str:
    text = " ".join(str(value or "").split())
    if len(text) <= max_chars:
        return text
    return text[: max_chars - 3].rstrip() + "..."


def _review_assist_preview_list(
    value: Any,
    *,
    max_items: int = 3,
    max_chars: int = 96,
) -> tuple[str, ...]:
    return tuple(
        _review_assist_preview(item, max_chars=max_chars)
        for item in _ensure_list(value)[:max_items]
        if str(item or "").strip()
    )


def _markdown_table_cell(value: Any, *, max_chars: int = 96) -> str:
    if isinstance(value, Mapping):
        text = json.dumps(dict(value), ensure_ascii=False, sort_keys=True)
    elif isinstance(value, (list, tuple, set)):
        text = ", ".join(str(item) for item in value)
    else:
        text = str(value or "")
    return _review_assist_preview(text, max_chars=max_chars).replace("|", "\\|") or "-"


def _negative_example_int(value: Any) -> int:
    try:
        return int(value or 0)
    except (TypeError, ValueError):
        return 0


def _negative_example_positive_ids(
    rows: Sequence[Mapping[str, Any]],
    *,
    expected_positive_minimum_target: int,
) -> set[str]:
    positive_ids = {
        str(row.get("negative_example_id") or "")
        for row in rows
        if str(row.get("negative_example_id") or "").strip()
        and _negative_example_int(row.get("extracted_footprint_count")) > 0
    }
    if len(positive_ids) >= int(expected_positive_minimum_target):
        return positive_ids

    candidates = sorted(
        rows,
        key=lambda row: (
            -_negative_example_int(row.get("priority_score")),
            str(row.get("source_id") or ""),
        ),
    )
    for row in candidates:
        negative_example_id = str(row.get("negative_example_id") or "").strip()
        if not negative_example_id or negative_example_id in positive_ids:
            continue
        focus = str(row.get("suggested_review_focus") or "")
        if focus not in {
            "claims_without_extracted_footprints",
            "no_extracted_footprints",
            "claims_with_extracted_footprints",
        }:
            continue
        positive_ids.add(negative_example_id)
        if len(positive_ids) >= int(expected_positive_minimum_target):
            break
    return positive_ids


def _negative_example_approval_draft_note(
    row: Mapping[str, Any],
    *,
    expected_footprint_present: bool,
    extracted_footprint_found: bool,
) -> str:
    focus = str(row.get("suggested_review_focus") or "")
    details = [
        "machine-suggested negative-example recall decision",
        f"focus={focus or 'unknown'}",
        f"forecast_claim_count={_negative_example_int(row.get('forecast_claim_count'))}",
        (
            "extracted_footprint_count="
            f"{_negative_example_int(row.get('extracted_footprint_count'))}"
        ),
        f"expected_footprint_present={str(expected_footprint_present).lower()}",
        f"extracted_footprint_found={str(extracted_footprint_found).lower()}",
        "human approval required before import",
    ]
    return "; ".join(details)


def _negative_example_approval_draft_row(
    row: Mapping[str, Any],
    *,
    expected_positive_ids: set[str],
) -> dict[str, Any]:
    negative_example_id = str(row.get("negative_example_id") or "").strip()
    extracted_footprint_found = (
        _negative_example_int(row.get("extracted_footprint_count")) > 0
    )
    expected_footprint_present = negative_example_id in expected_positive_ids
    return {
        "approval_draft_kind": (
            "analytical_footprint_negative_example_approval_draft_not_import"
        ),
        "not_apply_footprint_negative_examples_input": True,
        "approval_status": "pending_human_approval",
        "human_approval_required": True,
        "negative_example_id": negative_example_id,
        "source_id": str(row.get("source_id") or ""),
        "report_id": str(row.get("report_id") or ""),
        "sample_kind": str(row.get("sample_kind") or ""),
        "review_context_ref": str(row.get("review_context_ref") or ""),
        "target_row_hash": str(row.get("target_row_hash") or ""),
        "report_type": str(row.get("report_type") or ""),
        "sector": str(row.get("sector") or ""),
        "publish_date": str(row.get("publish_date") or ""),
        "forecast_claim_count": _negative_example_int(row.get("forecast_claim_count")),
        "extracted_footprint_count": _negative_example_int(
            row.get("extracted_footprint_count")
        ),
        "suggested_review_focus": str(row.get("suggested_review_focus") or ""),
        "priority_score": _negative_example_int(row.get("priority_score")),
        "expected_footprint_present": expected_footprint_present,
        "extracted_footprint_found": extracted_footprint_found,
        "source_text_included": False,
        "reviewer": "",
        "review_date": "",
        "review_notes": _negative_example_approval_draft_note(
            row,
            expected_footprint_present=expected_footprint_present,
            extracted_footprint_found=extracted_footprint_found,
        ),
        "policy": (
            "private approval draft only; user must approve before values are "
            "copied to the analytical footprint negative-example recall input"
        ),
    }


def _negative_example_decision_counts(
    rows: Sequence[Mapping[str, Any]],
) -> dict[str, dict[str, int]]:
    counts: dict[str, Counter[str]] = {
        "expected_footprint_present": Counter(),
        "extracted_footprint_found": Counter(),
    }
    for row in rows:
        for field in counts:
            value = row.get(field)
            if value is True:
                counts[field]["true"] += 1
            elif value is False:
                counts[field]["false"] += 1
            else:
                counts[field]["null"] += 1
    return {field: dict(counter) for field, counter in counts.items()}


def _negative_example_recall_counts(rows: Sequence[Mapping[str, Any]]) -> dict[str, int]:
    positive_count = sum(1 for row in rows if row.get("expected_footprint_present") is True)
    true_positive_count = sum(
        1
        for row in rows
        if row.get("expected_footprint_present") is True
        and row.get("extracted_footprint_found") is True
    )
    return {
        "positive_count": positive_count,
        "true_positive_count": true_positive_count,
        "false_negative_count": max(0, positive_count - true_positive_count),
    }


def render_analytical_footprint_negative_example_approval_draft_markdown(
    report: AnalyticalFootprintNegativeExampleApprovalDraftReport,
    rows: Sequence[Mapping[str, Any]],
) -> str:
    headers = (
        "#",
        "negative_example_id",
        "report_type",
        "focus",
        "claims",
        "footprints",
        "expected",
        "found",
    )
    lines = [
        "# RKE Analytical Footprint Negative Example Approval Draft",
        "",
        f"- Report ID: {report.report_id}",
        f"- Rows: {report.row_count}",
        f"- Input: `{report.input_path}`",
        f"- JSONL draft: `{report.jsonl_path}`",
        "",
        "This private file contains machine suggestions for human approval. It is not an import file.",
        "Approve or edit decisions before copying them into the official negative-example input.",
        "",
        "## Proposed Counts",
        "",
    ]
    for field, counter in report.proposed_decision_counts.items():
        lines.append(f"- `{field}`: {_markdown_table_cell(counter, max_chars=160)}")
    lines.append(
        "- `recall_counts`: "
        + _markdown_table_cell(report.proposed_recall_counts, max_chars=240)
    )
    lines.extend(
        [
            "",
            "## Approval Checklist",
            "",
            "| " + " | ".join(headers) + " |",
            "| " + " | ".join("---" for _ in headers) + " |",
        ]
    )
    for index, row in enumerate(rows, 1):
        cells = [
            str(index),
            f"`{row.get('negative_example_id')}`",
            _markdown_table_cell(row.get("report_type"), max_chars=40),
            _markdown_table_cell(row.get("suggested_review_focus"), max_chars=48),
            str(row.get("forecast_claim_count") or 0),
            str(row.get("extracted_footprint_count") or 0),
            str(row.get("expected_footprint_present")).lower(),
            str(row.get("extracted_footprint_found")).lower(),
        ]
        lines.append("| " + " | ".join(cells) + " |")
    if report.blockers:
        lines.extend(["", "## Blockers", ""])
        lines.extend(f"- {blocker}" for blocker in report.blockers)
    return "\n".join(lines)


def write_analytical_footprint_negative_example_approval_draft(
    root: str | Path = ".",
    *,
    input_path: str | Path = ANALYTICAL_FOOTPRINT_NEGATIVE_EXAMPLES_PATH,
    expected_positive_minimum_target: int = 50,
) -> AnalyticalFootprintNegativeExampleApprovalDraftReport:
    root_path = Path(root)
    input_text = str(input_path)
    resolved_input_path = Path(input_path)
    if not resolved_input_path.is_absolute():
        resolved_input_path = root_path / resolved_input_path
    input_rows_raw, parse_blockers = load_jsonl_with_errors(
        resolved_input_path,
        label="analytical footprint negative example approval draft input",
    )
    rows, invalid_rows = _split_mapping_rows(input_rows_raw)
    blockers = [*parse_blockers]
    if invalid_rows:
        blockers.append(
            "analytical footprint negative example approval draft input row must "
            "be object at row(s): "
            + ", ".join(str(row_number) for row_number in invalid_rows)
        )
    if not input_rows_raw:
        blockers.append("analytical footprint negative example input is empty")

    expected_positive_ids = _negative_example_positive_ids(
        rows,
        expected_positive_minimum_target=expected_positive_minimum_target,
    )
    draft_rows = tuple(
        _negative_example_approval_draft_row(
            row,
            expected_positive_ids=expected_positive_ids,
        )
        for row in rows
    )
    report = AnalyticalFootprintNegativeExampleApprovalDraftReport(
        report_id=(
            "RKE-REPORT-INTELLIGENCE-FOOTPRINT-NEGATIVE-EXAMPLE-APPROVAL-DRAFT"
        ),
        input_path=input_text,
        jsonl_path=ANALYTICAL_FOOTPRINT_NEGATIVE_EXAMPLE_APPROVAL_DRAFT_JSONL_PATH,
        markdown_path=ANALYTICAL_FOOTPRINT_NEGATIVE_EXAMPLE_APPROVAL_DRAFT_MD_PATH,
        row_count=len(draft_rows),
        pending_approval_rows=sum(
            1 for row in draft_rows if row.get("approval_status") != "approved"
        ),
        expected_positive_minimum_target=int(expected_positive_minimum_target),
        proposed_decision_counts=_negative_example_decision_counts(draft_rows),
        proposed_recall_counts=_negative_example_recall_counts(draft_rows),
        blockers=tuple(blockers),
        policy=(
            "private machine suggestion draft only; formal negative-example "
            "fields require human approval before recall computation"
        ),
    )
    _write_jsonl(
        root_path / ANALYTICAL_FOOTPRINT_NEGATIVE_EXAMPLE_APPROVAL_DRAFT_JSONL_PATH,
        draft_rows,
    )
    markdown_path = (
        root_path / ANALYTICAL_FOOTPRINT_NEGATIVE_EXAMPLE_APPROVAL_DRAFT_MD_PATH
    )
    markdown_path.parent.mkdir(parents=True, exist_ok=True)
    markdown_path.write_text(
        render_analytical_footprint_negative_example_approval_draft_markdown(
            report,
            draft_rows,
        )
        + "\n",
        encoding="utf-8",
    )
    return report


def write_analytical_footprint_negative_example_approved_import(
    root: str | Path = ".",
    *,
    approval_draft_path: str | Path = (
        ANALYTICAL_FOOTPRINT_NEGATIVE_EXAMPLE_APPROVAL_DRAFT_JSONL_PATH
    ),
    output_path: str | Path = ANALYTICAL_FOOTPRINT_NEGATIVE_EXAMPLES_PATH,
    reviewer: str,
    review_date: str,
    overwrite: bool = False,
) -> AnalyticalFootprintNegativeExampleApprovedImportReport:
    root_path = Path(root)
    resolved_approval_draft_path = Path(approval_draft_path)
    if not resolved_approval_draft_path.is_absolute():
        resolved_approval_draft_path = root_path / resolved_approval_draft_path
    resolved_output_path = Path(output_path)
    if not resolved_output_path.is_absolute():
        resolved_output_path = root_path / resolved_output_path

    blockers: list[str] = []
    reviewer_value = str(reviewer or "").strip()
    review_date_value = str(review_date or "").strip()
    if not reviewer_value:
        blockers.append("reviewer required")
    if not review_date_value:
        blockers.append("review_date required")
    else:
        blockers.extend(
            _review_date_failures({"review_date": review_date_value}, "review_date")
        )
    if resolved_output_path.exists() and not overwrite:
        blockers.append(f"output_path already exists: {resolved_output_path}")

    draft_rows_raw, draft_parse_blockers = load_jsonl_with_errors(
        resolved_approval_draft_path,
        label="analytical footprint negative example approval draft",
    )
    target_rows_raw, target_parse_blockers = load_jsonl_with_errors(
        resolved_output_path,
        label="analytical footprint negative example target",
    )
    draft_rows, invalid_draft_rows = _split_mapping_rows(draft_rows_raw)
    target_rows, invalid_target_rows = _split_mapping_rows(target_rows_raw)
    blockers.extend(draft_parse_blockers)
    blockers.extend(target_parse_blockers)
    if invalid_draft_rows:
        blockers.append(
            "analytical footprint negative example approval draft row must be "
            "object at row(s): "
            + ", ".join(str(row_number) for row_number in invalid_draft_rows)
        )
    if invalid_target_rows:
        blockers.append(
            "analytical footprint negative example target row must be object at "
            "row(s): " + ", ".join(str(row_number) for row_number in invalid_target_rows)
        )
    if not draft_rows_raw:
        blockers.append("analytical footprint negative example approval draft is empty")

    target_by_id = {
        str(row.get("negative_example_id") or ""): row
        for row in target_rows
        if str(row.get("negative_example_id") or "").strip()
    }
    seen_ids: set[str] = set()
    output_rows: list[dict[str, Any]] = []
    for row_index, draft_row in enumerate(draft_rows, 1):
        negative_example_id = str(draft_row.get("negative_example_id") or "").strip()
        if not negative_example_id:
            blockers.append(
                f"approval draft row {row_index}.negative_example_id required"
            )
            continue
        if negative_example_id in seen_ids:
            blockers.append(
                f"approval draft row {row_index}.negative_example_id duplicate"
            )
            continue
        seen_ids.add(negative_example_id)
        target_row = target_by_id.get(negative_example_id)
        if target_row is None:
            blockers.append(
                f"approval draft row {row_index}.negative_example_id missing from target"
            )
            continue
        draft_hash = str(draft_row.get("target_row_hash") or "").strip()
        target_hash = str(target_row.get("target_row_hash") or "").strip()
        if draft_hash and target_hash and draft_hash != target_hash:
            blockers.append(f"approval draft row {row_index}.target_row_hash mismatch")
        expected = draft_row.get("expected_footprint_present")
        found = draft_row.get("extracted_footprint_found")
        if not isinstance(expected, bool):
            blockers.append(
                "approval draft row "
                f"{row_index}.expected_footprint_present must be boolean"
            )
            continue
        if not isinstance(found, bool):
            blockers.append(
                f"approval draft row {row_index}.extracted_footprint_found must be boolean"
            )
            continue
        approved_row = dict(target_row)
        approved_row["expected_footprint_present"] = expected
        approved_row["extracted_footprint_found"] = found
        approved_row["reviewer"] = reviewer_value
        approved_row["review_date"] = review_date_value
        approved_row["review_notes"] = _approval_draft_review_note(
            draft_row,
            reviewer=reviewer_value,
            review_date=review_date_value,
        )
        approved_row["source_text_included"] = False
        output_rows.append(approved_row)

    backup_path = ""
    backed_up_existing_output = False
    if not blockers:
        if overwrite and resolved_output_path.exists():
            backup = _manual_review_backup_path(root_path, resolved_output_path)
            backup.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(resolved_output_path, backup)
            backup_path = str(backup)
            backed_up_existing_output = True
        _write_jsonl(resolved_output_path, output_rows)

    return AnalyticalFootprintNegativeExampleApprovedImportReport(
        report_id=(
            "RKE-REPORT-INTELLIGENCE-FOOTPRINT-NEGATIVE-EXAMPLE-APPROVED-IMPORT"
        ),
        approval_draft_path=str(resolved_approval_draft_path),
        output_path=str(resolved_output_path),
        accepted=not blockers,
        reviewer=reviewer_value,
        review_date=review_date_value,
        input_rows=len(draft_rows_raw),
        output_rows=len(output_rows),
        approved_rows=len(output_rows) if not blockers else 0,
        proposed_decision_counts=_negative_example_decision_counts(output_rows),
        proposed_recall_counts=_negative_example_recall_counts(output_rows),
        blockers=tuple(blockers),
        backed_up_existing_output=backed_up_existing_output,
        backup_path=backup_path,
    )


def _footprint_review_assist_row(index: int, row: Mapping[str, Any]) -> dict[str, Any]:
    return {
        "assist_kind": "analytical_footprint_review_assist_not_import",
        "not_apply_footprint_review_input": True,
        "index": index,
        "footprint_id": str(row.get("footprint_id") or ""),
        "target_row_hash": str(row.get("target_row_hash") or ""),
        "source_id": str(row.get("source_id") or ""),
        "report_id": str(row.get("report_id") or ""),
        "sector": str(row.get("sector") or ""),
        "extraction_type": str(row.get("extraction_type") or ""),
        "topic_preview": _review_assist_preview(row.get("topic_preview"), max_chars=96),
        "indicator_mentions_preview": _review_assist_preview_list(
            row.get("indicator_mentions_review_preview"),
            max_items=3,
            max_chars=80,
        ),
        "indicator_mentions_summary": _footprint_review_indicator_summary(row),
        "analysis_patterns_preview": _review_assist_preview_list(
            row.get("analysis_patterns_review_preview"),
            max_items=3,
            max_chars=80,
        ),
        "target_entity_candidates": tuple(
            _review_assist_preview(item, max_chars=48)
            for item in _ensure_list(row.get("target_entity_candidates"))[:5]
            if str(item or "").strip()
        ),
        "target_agent_candidates": tuple(
            _review_assist_preview(item, max_chars=48)
            for item in _ensure_list(row.get("target_agent_candidates"))[:5]
            if str(item or "").strip()
        ),
        "source_span_count": len(_ensure_list(row.get("source_span_ids"))),
        "review_context_ref": str(row.get("review_context_ref") or ""),
        "target_review_path": ANALYTICAL_FOOTPRINT_REVIEW_TEMPLATE_PATH,
        "reviewed_import_path": ANALYTICAL_FOOTPRINT_REVIEWED_IMPORT_PATH,
        "human_required_fields": (
            *ANALYTICAL_FOOTPRINT_REVIEW_REQUIRED_FIELDS,
            "manual_error_tags",
        ),
        "human_review_required": True,
    }


def _select_analytical_footprint_review_rows_for_input(
    root_path: Path,
    target_rows: Sequence[Mapping[str, Any]],
    review_input_path: str | Path | None,
) -> tuple[list[Mapping[str, Any]], list[str], str, str]:
    if review_input_path is None:
        return (
            [row for row in target_rows if not _footprint_review_row_complete(row)],
            [],
            "pending_template",
            "",
        )

    review_input_text = str(review_input_path)
    input_rows_raw, input_parse_blockers = load_jsonl_with_errors(
        root_path / review_input_text,
        label="analytical footprint review input",
    )
    input_rows, invalid_input_rows = _split_mapping_rows(input_rows_raw)
    blockers: list[str] = [*input_parse_blockers]
    if invalid_input_rows:
        blockers.append(
            "analytical footprint review input row must be object at row(s): "
            + ", ".join(str(row_number) for row_number in invalid_input_rows)
        )
    if not input_rows_raw:
        blockers.append("analytical footprint review input is missing or empty")

    target_by_id = {
        str(row.get("footprint_id") or ""): row
        for row in target_rows
        if str(row.get("footprint_id") or "").strip()
    }
    selected_rows: list[Mapping[str, Any]] = []
    seen_footprint_ids: set[str] = set()
    for row_index, input_row in enumerate(input_rows, 1):
        footprint_id = str(input_row.get("footprint_id") or "").strip()
        if not footprint_id:
            blockers.append(
                f"analytical footprint review input row {row_index}.footprint_id: required"
            )
            continue
        if footprint_id in seen_footprint_ids:
            blockers.append(
                "analytical footprint review input row "
                f"{row_index}.footprint_id: duplicate {footprint_id}"
            )
            continue
        seen_footprint_ids.add(footprint_id)
        target_row = target_by_id.get(footprint_id)
        if target_row is None:
            blockers.append(
                "analytical footprint review input row "
                f"{row_index}.footprint_id: no matching target review row"
            )
            continue
        input_hash = str(input_row.get("target_row_hash") or "").strip()
        target_hash = str(target_row.get("target_row_hash") or "").strip()
        if input_hash and target_hash and input_hash != target_hash:
            blockers.append(
                "analytical footprint review input row "
                f"{row_index}.target_row_hash: does not match target review row"
            )
        selected_rows.append(target_row)
    return selected_rows, blockers, "review_input", review_input_text


def build_analytical_footprint_review_assist(
    root: str | Path = ".",
    *,
    review_input_path: str | Path | None = None,
) -> tuple[AnalyticalFootprintReviewAssistReport, tuple[Mapping[str, Any], ...]]:
    root_path = Path(root)
    target_path = root_path / ANALYTICAL_FOOTPRINT_REVIEW_TEMPLATE_PATH
    target_rows_raw, target_parse_blockers = load_jsonl_with_errors(
        target_path,
        label="analytical footprint target review",
    )
    target_rows, invalid_target_rows = _split_mapping_rows(target_rows_raw)
    pending_rows, input_blockers, selection_source, review_input_text = (
        _select_analytical_footprint_review_rows_for_input(
            root_path,
            target_rows,
            review_input_path,
        )
    )
    assist_rows = tuple(
        _footprint_review_assist_row(index, row)
        for index, row in enumerate(pending_rows, 1)
    )
    review_summary = build_analytical_footprint_review_summary(target_rows)
    quality_gap_targets = _footprint_review_quality_gap_targets_from_summary(
        review_summary
    )
    blockers: list[str] = [*target_parse_blockers, *input_blockers]
    if invalid_target_rows:
        blockers.append(
            "analytical footprint target review row must be object at row(s): "
            + ", ".join(str(row_number) for row_number in invalid_target_rows)
        )
    if not target_rows_raw:
        blockers.append("analytical footprint review template is empty")
    elif not target_rows:
        blockers.append("analytical footprint review template has no valid rows")
    return (
        AnalyticalFootprintReviewAssistReport(
            report_id="RKE-REPORT-INTELLIGENCE-FOOTPRINT-REVIEW-ASSIST",
            target_path=ANALYTICAL_FOOTPRINT_REVIEW_TEMPLATE_PATH,
            reviewed_import_path=ANALYTICAL_FOOTPRINT_REVIEWED_IMPORT_PATH,
            jsonl_path=ANALYTICAL_FOOTPRINT_REVIEW_ASSIST_JSONL_PATH,
            markdown_path=ANALYTICAL_FOOTPRINT_REVIEW_WORKBOOK_MD_PATH,
            row_count=len(assist_rows),
            pending_rows=len(pending_rows),
            blockers=tuple(blockers),
            selection_source=selection_source,
            review_input_path=review_input_text,
            quality_gap_targets=quality_gap_targets,
        ),
        assist_rows,
    )


def render_analytical_footprint_review_workbook_markdown(
    report: AnalyticalFootprintReviewAssistReport,
    rows: Sequence[Mapping[str, Any]],
) -> str:
    lines = [
        "# RKE Analytical Footprint Review Workbook",
        "",
        f"- Assist ID: {report.report_id}",
        f"- Pending rows: {report.pending_rows}",
        f"- Selection source: `{report.selection_source}`",
        f"- Review template: `{report.target_path}`",
        f"- Reviewed import target: `{report.reviewed_import_path}`",
        f"- JSONL assist: `{report.jsonl_path}`",
        "",
        "This workbook is private review assistance only. It is not an import file and does not satisfy the analytical-footprint review gate.",
        "Fill reviewer decisions only in the reviewed JSONL scratch file, then dry-run `mosaic-rke apply-footprint-review`.",
        "",
    ]
    if report.blockers:
        lines.extend(["## Blockers", ""])
        lines.extend(f"- {blocker}" for blocker in report.blockers)
        lines.append("")
    if report.quality_gap_targets:
        lines.extend(["## Quality Gate Gap Targets", ""])
        lines.append(
            "Aggregate only; these counts contain no source text and are not import decisions."
        )
        lines.append("")
        sample_size = report.quality_gap_targets.get(
            "sample_size_completed_rows",
            {},
        )
        if isinstance(sample_size, Mapping):
            lines.append(
                "- Completed rows in denominator: "
                f"{sample_size.get('current_count')}"
            )
        metrics = report.quality_gap_targets.get("metrics", {})
        if isinstance(metrics, Mapping):
            for metric, target in metrics.items():
                if not isinstance(target, Mapping) or target.get("is_passing") is True:
                    continue
                lines.append(
                    "- "
                    f"{metric}: {target.get('current_rate')} / {target.get('threshold')} "
                    f"(pass count {target.get('current_pass_count')}/"
                    f"{target.get('required_pass_count')}, need +"
                    f"{target.get('minimum_additional_pass_count_if_denominator_unchanged')})"
                )
        lines.append("")
    lines.extend(
        [
            "## Pending Footprints",
            "",
            (
                "| # | footprint_id | target_hash | source_id | sector | type | "
                "source_spans | topic | indicators | analysis_patterns | entities | agents |"
            ),
            "|---|---|---|---|---|---|---|---|---|---|---|---|",
        ]
    )
    for row in rows:
        lines.append(
            "| "
            + " | ".join(
                (
                    _markdown_table_cell(row.get("index"), max_chars=12),
                    _markdown_table_cell(row.get("footprint_id"), max_chars=48),
                    _markdown_table_cell(row.get("target_row_hash"), max_chars=24),
                    _markdown_table_cell(row.get("source_id"), max_chars=48),
                    _markdown_table_cell(row.get("sector"), max_chars=32),
                    _markdown_table_cell(row.get("extraction_type"), max_chars=24),
                    _markdown_table_cell(row.get("source_span_count"), max_chars=12),
                    _markdown_table_cell(row.get("topic_preview"), max_chars=96),
                    _markdown_table_cell(row.get("indicator_mentions_preview"), max_chars=96),
                    _markdown_table_cell(row.get("analysis_patterns_preview"), max_chars=96),
                    _markdown_table_cell(row.get("target_entity_candidates"), max_chars=72),
                    _markdown_table_cell(row.get("target_agent_candidates"), max_chars=72),
                )
            )
            + " |"
        )
    return "\n".join(lines)


def write_analytical_footprint_review_assist(
    root: str | Path = ".",
    *,
    review_input_path: str | Path | None = None,
) -> AnalyticalFootprintReviewAssistReport:
    root_path = Path(root)
    report, rows = build_analytical_footprint_review_assist(
        root_path,
        review_input_path=review_input_path,
    )
    _write_jsonl(root_path / ANALYTICAL_FOOTPRINT_REVIEW_ASSIST_JSONL_PATH, rows)
    markdown_path = root_path / ANALYTICAL_FOOTPRINT_REVIEW_WORKBOOK_MD_PATH
    markdown_path.parent.mkdir(parents=True, exist_ok=True)
    markdown_path.write_text(
        render_analytical_footprint_review_workbook_markdown(report, rows) + "\n",
        encoding="utf-8",
    )
    return report


def _footprint_review_priority_reasons(row: Mapping[str, Any]) -> tuple[str, ...]:
    reasons: list[str] = []
    indicator_mentions = _ensure_list(row.get("indicator_mentions_review_preview"))
    analysis_patterns = _ensure_list(row.get("analysis_patterns_review_preview"))
    if not indicator_mentions:
        reasons.append("missing_indicator_mentions")
    if len(analysis_patterns) >= 3:
        reasons.append("complex_multi_step_patterns")
    if not _ensure_list(row.get("target_entity_candidates")):
        reasons.append("missing_target_entity_candidates")
    if not _ensure_list(row.get("target_agent_candidates")):
        reasons.append("missing_target_agent_candidates")
    if len(_ensure_list(row.get("source_span_ids"))) > 3:
        reasons.append("many_source_spans")
    return tuple(reasons)


FOOTPRINT_REVIEW_PRIORITY_REASON_WEIGHTS: Mapping[str, int] = {
    "missing_indicator_mentions": 3,
    "complex_multi_step_patterns": 2,
    "missing_target_entity_candidates": 2,
    "missing_target_agent_candidates": 1,
    "many_source_spans": 1,
}


def _footprint_review_priority_score(row: Mapping[str, Any]) -> int:
    return sum(
        FOOTPRINT_REVIEW_PRIORITY_REASON_WEIGHTS.get(reason, 0)
        for reason in _footprint_review_priority_reasons(row)
    )


def _footprint_review_evidence_terms(row: Mapping[str, Any]) -> tuple[str, ...]:
    raw_terms: list[str] = []
    for value in (
        row.get("sector"),
        row.get("topic_preview"),
        *_ensure_list(row.get("analysis_patterns_review_preview")),
        *_ensure_list(row.get("indicator_mentions_review_preview")),
        *_ensure_list(row.get("target_entity_candidates")),
    ):
        text = str(value or "").strip()
        if not text:
            continue
        raw_terms.append(text)
        raw_terms.extend(re.findall(r"[\u4e00-\u9fff]{2,}|[A-Za-z][A-Za-z0-9+\-/ ]{2,}", text))
    raw_terms.extend(
        [
            "营收",
            "归母净利润",
            "毛利率",
            "净利率",
            "同比",
            "环比",
            "销售额",
            "销量",
            "均价",
            "价格",
            "市场",
            "行业",
            "需求",
            "供给",
            "产量",
            "库存",
            "利润",
            "估值",
            "PE",
            "ROE",
            "PMI",
            "政策",
            "产业链",
            "竞争",
            "风险",
        ]
    )
    seen: list[str] = []
    for term in raw_terms:
        normalized = " ".join(str(term or "").split())
        if not normalized or normalized in seen or len(normalized) > 96:
            continue
        seen.append(normalized)
    return tuple(seen)


def _footprint_review_evidence_snippets(
    markdown_text: str,
    terms: Sequence[str],
    *,
    max_snippets: int = 2,
    max_chars: int = 900,
) -> tuple[dict[str, Any], ...]:
    snippets: list[dict[str, Any]] = []
    used_offsets: list[int] = []
    for term in terms:
        match = re.search(re.escape(term), markdown_text, re.IGNORECASE)
        if match is None:
            continue
        offset = int(match.start())
        if any(abs(offset - used) < max_chars for used in used_offsets):
            continue
        start = max(0, offset - max_chars // 3)
        end = min(len(markdown_text), offset + max_chars)
        snippets.append(
            {
                "matched_term": term,
                "start_char": start,
                "end_char": end,
                "snippet": " ".join(markdown_text[start:end].split()),
            }
        )
        used_offsets.append(offset)
        if len(snippets) >= max_snippets:
            break
    if not snippets and markdown_text:
        snippets.append(
            {
                "matched_term": "document_head",
                "start_char": 0,
                "end_char": min(len(markdown_text), max_chars),
                "snippet": " ".join(markdown_text[:max_chars].split()),
            }
        )
    return tuple(snippets)


def _footprint_review_metric_mapping_diagnostics(
    row: Mapping[str, Any],
) -> dict[str, Any]:
    summary = _footprint_review_indicator_summary(row)
    mention_count = int(summary.get("mention_count") or 0)
    unknown_count = int(summary.get("unknown_canonical_count") or 0)
    ungrounded_count = int(summary.get("ungrounded_count") or 0)
    complete_count = int(summary.get("complete_source_grounded_count") or 0)
    mapping_complete = (
        mention_count > 0 and unknown_count == 0 and ungrounded_count == 0
    )
    return {
        "mention_count": mention_count,
        "preview_count": int(summary.get("preview_count") or 0),
        "preview_limit": int(summary.get("preview_limit") or 0),
        "hidden_count": int(summary.get("hidden_count") or 0),
        "unknown_canonical_count": unknown_count,
        "ungrounded_count": ungrounded_count,
        "complete_source_grounded_count": complete_count,
        "hidden_unknown_canonical_count": int(
            summary.get("hidden_unknown_canonical_count") or 0
        ),
        "hidden_ungrounded_count": int(summary.get("hidden_ungrounded_count") or 0),
        "mapping_complete": mapping_complete,
        "diagnostic_source": str(summary.get("summary_source") or "unknown"),
    }


def _footprint_review_quality_gap_focus_fields(
    *,
    boilerplate_risk_footprint: bool,
    markdown_exists: bool,
    has_span_evidence: bool,
    has_patterns: bool,
    metric_mapping_diagnostics: Mapping[str, Any],
    inferred_indicator_suggestions: Sequence[Mapping[str, Any]],
) -> tuple[str, ...]:
    fields: list[str] = []
    if boilerplate_risk_footprint:
        fields.extend(
            (
                "footprint_correct",
                "metric_mapping_correct",
                "inferred_steps_tagged_correctly",
            )
        )
    if not markdown_exists or not has_span_evidence:
        fields.append("source_span_supports_footprint")
    if not has_patterns:
        fields.append("inferred_steps_tagged_correctly")
    if (
        metric_mapping_diagnostics.get("mapping_complete") is not True
        or bool(inferred_indicator_suggestions)
    ):
        fields.append("metric_mapping_correct")
    if not bool(metric_mapping_diagnostics.get("mention_count")):
        fields.append("unknowns_used_when_uncertain")
    elif bool(metric_mapping_diagnostics.get("unknown_canonical_count")):
        fields.append("unknowns_used_when_uncertain")
    elif bool(metric_mapping_diagnostics.get("hidden_unknown_canonical_count")):
        fields.append("unknowns_used_when_uncertain")
    return tuple(dict.fromkeys(fields))


